SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): Ampere''s circuital law is valid for all closed loops, regardless of their shape.\nReason (R): The magnetic field B⃗ is always constant in magnitude on any Amperian loop.", "explanation": "A is true — Ampere''s law ∮B⃗·dl⃗ = μ₀I_enc holds for any closed loop of any shape. R is false — B is constant only on loops with appropriate symmetry (e.g., circular loop around a straight wire). For an arbitrary shaped loop, B varies along the loop. Since A is true and R is false, the answer is C.", "correct_answer": "C", "concept_tags": ["assertion-reasoning", "loop-shape", "field-constancy"], "payload": {"question_id": "cuet-phy-mag-ampere-27", "subtopic": "Amperian loop", "topic_name": "Ampere''s Circuital Law", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are true and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are true but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": true}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "R is false. B is not constant on every Amperian loop — only on those with special symmetry (like circular loops around a straight wire).", "misconception": "Thinking B must be constant on any Amperian loop"}, {"option_key": "B", "hint": "R is false, so this option is ruled out. B varies along irregular-shaped loops.", "misconception": "Not recognizing that B varies on non-symmetric loops"}, {"option_key": "D", "hint": "A is true — Ampere''s law holds for any closed loop. The law is general; only practical computation of B requires symmetry.", "misconception": "Confusing the validity of the law with its computational ease"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): Ampere''s circuital law in its original form fails to explain the continuity of current between the plates of a charging capacitor.\nReason (R): Between the capacitor plates, the conduction current is zero but a changing electric field exists, which is not accounted for in the original Ampere''s law.", "explanation": "Both A and R are true, and R correctly explains A. When a capacitor is charging, the conduction current flows in the wire but there is no conduction current between the plates. The original Ampere''s law gives contradictory results depending on the surface chosen for the Amperian loop. Maxwell resolved this by introducing displacement current (ε₀dΦ_E/dt) to account for the changing electric field between the plates.", "correct_answer": "A", "concept_tags": ["assertion-reasoning", "displacement-current", "limitations", "maxwell-modification"], "payload": {"question_id": "cuet-phy-mag-ampere-28", "subtopic": "Limitations", "topic_name": "Ampere''s Circuital Law", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are true and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are true but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly explains why A is true — the failure is precisely because the changing E field (displacement current) is not in the original law.", "misconception": "Not connecting the missing displacement current term to the failure"}, {"option_key": "C", "hint": "R is true — between the plates there is indeed no conduction current but a changing E field, and the original law ignores this.", "misconception": "Thinking conduction current flows between capacitor plates"}, {"option_key": "D", "hint": "A is true — the original Ampere''s law gives inconsistent results for the charging capacitor, which is a well-known limitation.", "misconception": "Denying the limitation of the original Ampere''s law"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the following current configurations (Column I) with the magnetic field expressions obtained using Ampere''s circuital law (Column II):", "explanation": "1→Q: For an infinite straight wire, B = μ₀I/(2πr). 2→R: Inside a solenoid, B = μ₀nI (uniform). 3→P: Inside a toroid at radius r, B = μ₀NI/(2πr). 4→S: Outside an ideal solenoid, B = 0.", "correct_answer": "C", "concept_tags": ["matching", "field-formulas", "configurations"], "payload": {"question_id": "cuet-phy-mag-ampere-29", "subtopic": "Application to infinite wire", "topic_name": "Ampere''s Circuital Law", "bloom_level": "remember", "options": [{"key": "A", "text": "1→P, 2→R, 3→Q, 4→S", "is_correct": false}, {"key": "B", "text": "1→R, 2→Q, 3→P, 4→S", "is_correct": false}, {"key": "C", "text": "1→Q, 2→R, 3→P, 4→S", "is_correct": true}, {"key": "D", "text": "1→Q, 2→S, 3→P, 4→R", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Item 1 (infinite wire) gives B = μ₀I/(2πr) = Q, not P. P has N (total turns) in the formula, which is for a toroid.", "misconception": "Confusing the wire formula with the toroid formula"}, {"option_key": "B", "hint": "Item 1 (infinite wire) gives B = μ₀I/(2πr) = Q, and item 2 (solenoid) gives B = μ₀nI = R. This option swaps them.", "misconception": "Swapping solenoid and wire expressions"}, {"option_key": "D", "hint": "Item 2 (inside solenoid) has B = μ₀nI ≠ 0. The field is zero only outside the solenoid (item 4).", "misconception": "Placing zero field inside the solenoid instead of outside"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match the following Amperian loop regions for a solid cylindrical conductor of radius R carrying current I (Column I) with the corresponding magnetic field behaviour (Column II):", "explanation": "1→R: At r = 0 (on the axis), by symmetry B = 0. 2→P: For r < R, B = μ₀Ir/(2πR²) ∝ r (linear increase). 3→S: At r = R, B = μ₀I/(2πR), maximum value. 4→Q: For r > R, B = μ₀I/(2πr) ∝ 1/r (hyperbolic decrease).", "correct_answer": "D", "concept_tags": ["matching", "cylindrical-conductor", "field-regions"], "payload": {"question_id": "cuet-phy-mag-ampere-30", "subtopic": "Application to infinite wire", "topic_name": "Ampere''s Circuital Law", "bloom_level": "analyze", "options": [{"key": "A", "text": "1→R, 2→Q, 3→S, 4→P", "is_correct": false}, {"key": "B", "text": "1→P, 2→R, 3→S, 4→Q", "is_correct": false}, {"key": "C", "text": "1→R, 2→P, 3→Q, 4→S", "is_correct": false}, {"key": "D", "text": "1→R, 2→P, 3→S, 4→Q", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Inside the conductor (item 2), B increases linearly (P), not decreases as 1/r (Q). The 1/r decrease is for r > R.", "misconception": "Swapping internal and external field behaviors"}, {"option_key": "B", "hint": "At r = 0, B = 0 (R), not linear increase (P). The field starts at zero on the axis by symmetry.", "misconception": "Not recognizing zero field on the axis"}, {"option_key": "C", "hint": "At r = R, B is maximum (S), not decreasing as 1/r (Q). The transition from linear increase to 1/r decrease occurs at the surface.", "misconception": "Misidentifying the surface as a region of decrease"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The value of ∮B⃗·dl⃗ in Ampere''s circuital law depends on the shape of the Amperian loop.", "explanation": "This statement is FALSE. Ampere''s circuital law states ∮B⃗·dl⃗ = μ₀I_enclosed. The value of the line integral depends only on the net current enclosed by the loop, not on its shape. Whether the loop is circular, square, elliptical, or irregular, the integral is the same as long as the same currents are enclosed.", "correct_answer": "B", "concept_tags": ["true-false", "loop-shape-independence", "line-integral"], "payload": {"question_id": "cuet-phy-mag-ampere-31", "subtopic": "Line integral of B", "topic_name": "Ampere''s Circuital Law", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The line integral ∮B⃗·dl⃗ equals μ₀I_enclosed, which depends only on the enclosed current, not the loop shape. While B⃗ may vary along the loop, the integral is shape-independent.", "misconception": "Confusing the value of B at points on the loop with the total line integral"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The magnetic field inside an ideal solenoid is uniform and independent of the position inside the solenoid.", "explanation": "This statement is TRUE. For an ideal (infinite) solenoid, Ampere''s circuital law gives B = μ₀nI everywhere inside. The field does not depend on the radial position or the distance from either end (for an infinite solenoid). The field is uniform, directed along the axis, and has the same magnitude at all interior points.", "correct_answer": "A", "concept_tags": ["true-false", "solenoid", "uniform-field"], "payload": {"question_id": "cuet-phy-mag-ampere-32", "subtopic": "Application to solenoid", "topic_name": "Ampere''s Circuital Law", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "For an ideal infinite solenoid, B = μ₀nI is indeed constant throughout the interior. The field is uniform and does not vary with position inside.", "misconception": "Thinking the solenoid field varies radially like a toroid"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "medium", "question_text": "If ∮B⃗·dl⃗ = 0 for a closed Amperian loop, then the magnetic field B⃗ must be zero at every point on the loop.", "explanation": "This statement is FALSE. ∮B⃗·dl⃗ = 0 means the net enclosed current is zero, but this does not require B⃗ = 0 at every point. For example, consider two parallel wires carrying equal and opposite currents: the Amperian loop enclosing both has ∮B⃗·dl⃗ = 0, but B⃗ is non-zero at most points on the loop. The integral being zero only means the positive and negative contributions cancel.", "correct_answer": "B", "concept_tags": ["true-false", "zero-integral", "non-zero-field"], "payload": {"question_id": "cuet-phy-mag-ampere-33", "subtopic": "Line integral of B", "topic_name": "Ampere''s Circuital Law", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A zero line integral means the net enclosed current is zero, not that B⃗ = 0 everywhere. External currents can produce non-zero B⃗ on the loop while contributing zero net flux.", "misconception": "Equating zero integral with zero field at all points"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "medium", "question_text": "Ampere''s circuital law is the magnetic analogue of Gauss''s law in electrostatics, where the line integral of B⃗ plays the role of the surface integral of E⃗.", "explanation": "This statement is TRUE. Gauss''s law: ∮E⃗·dA⃗ = Q_enc/ε₀ (surface integral of E over a closed surface equals enclosed charge divided by ε₀). Ampere''s law: ∮B⃗·dl⃗ = μ₀I_enc (line integral of B around a closed loop equals μ₀ times enclosed current). Both relate a field integral to an enclosed source, and both are most useful with high symmetry.", "correct_answer": "A", "concept_tags": ["true-false", "gauss-law-analogy", "comparison"], "payload": {"question_id": "cuet-phy-mag-ampere-34", "subtopic": "Comparison with Gauss''s law", "topic_name": "Ampere''s Circuital Law", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The analogy is well-established: Gauss''s law uses surface integral of E⃗ with enclosed charge, while Ampere''s law uses line integral of B⃗ with enclosed current. Both exploit symmetry.", "misconception": "Not recognizing the structural similarity between the two laws"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "easy", "question_text": "According to Ampere''s circuital law, ∮B⃗·dl⃗ = ________, where I_enc is the net current enclosed by the Amperian loop.", "explanation": "Ampere''s circuital law states that the line integral of the magnetic field B⃗ around a closed Amperian loop equals μ₀ times the net current enclosed by the loop: ∮B⃗·dl⃗ = μ₀I_enc, where μ₀ = 4π × 10⁻⁷ T·m/A is the permeability of free space.", "correct_answer": "B", "concept_tags": ["fill-in-blanks", "ampere-law-statement", "formula"], "payload": {"question_id": "cuet-phy-mag-ampere-35", "subtopic": "Ampere''s law statement", "topic_name": "Ampere''s Circuital Law", "bloom_level": "remember", "options": [{"key": "A", "text": "μ₀I_enc/(4π)", "is_correct": false}, {"key": "B", "text": "μ₀I_enc", "is_correct": true}, {"key": "C", "text": "I_enc/μ₀", "is_correct": false}, {"key": "D", "text": "μ₀I_enc/(2π)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The factor 4π appears in Biot-Savart law (μ₀/4π), not in Ampere''s circuital law. The law simply gives μ₀I_enc.", "misconception": "Mixing Biot-Savart and Ampere''s law constants"}, {"option_key": "C", "hint": "In Gauss''s law, the constant appears in the denominator (Q/ε₀). In Ampere''s law, μ₀ multiplies I_enc: ∮B⃗·dl⃗ = μ₀I_enc.", "misconception": "Inverting the position of μ₀ by analogy with Gauss''s law"}, {"option_key": "D", "hint": "The 2π factor appears when solving for B of a specific configuration (e.g., B = μ₀I/2πr). The law itself is ∮B⃗·dl⃗ = μ₀I_enc without 2π.", "misconception": "Confusing the general law with a specific application result"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "The magnetic field at the centre of a toroid with N turns, mean circumference L, and carrying current I is B = ________.", "explanation": "For a toroid with mean circumference L = 2πR, applying Ampere''s law: B(2πR) = μ₀NI, so B = μ₀NI/(2πR) = μ₀NI/L. This can also be written as B = μ₀nI where n = N/L is the number of turns per unit length along the toroid''s circumference.", "correct_answer": "C", "concept_tags": ["fill-in-blanks", "toroid", "formula"], "payload": {"question_id": "cuet-phy-mag-ampere-36", "subtopic": "Application to toroid", "topic_name": "Ampere''s Circuital Law", "bloom_level": "apply", "options": [{"key": "A", "text": "μ₀NI", "is_correct": false}, {"key": "B", "text": "μ₀NI/(4πL)", "is_correct": false}, {"key": "C", "text": "μ₀NI/L", "is_correct": true}, {"key": "D", "text": "μ₀I/L", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is missing the division by the circumference L. The Amperian loop has length L = 2πR, so B = μ₀NI/L.", "misconception": "Forgetting the loop length in the denominator"}, {"option_key": "B", "hint": "The 4π factor is extraneous here. Since L = 2πR, B = μ₀NI/(2πR) = μ₀NI/L. No additional 4π appears.", "misconception": "Introducing an unnecessary 4π factor"}, {"option_key": "D", "hint": "The total number of turns N must be included. Each turn carries current I, so the enclosed current is NI, giving B = μ₀NI/L.", "misconception": "Forgetting the number of turns N"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "A researcher needs a uniform magnetic field of 0.02 T for an experiment. She decides to use a solenoid with 40 turns per cm and wants to determine the required current. What current must flow through the solenoid?", "explanation": "Converting n = 40 turns/cm = 4000 turns/m. Using B = μ₀nI: I = B/(μ₀n) = 0.02/(4π × 10⁻⁷ × 4000) = 0.02/(16π × 10⁻⁴) = 0.02/(5.027 × 10⁻³) ≈ 3.98 A ≈ 4 A.", "correct_answer": "D", "concept_tags": ["scenario", "solenoid", "numerical", "current-calculation"], "payload": {"question_id": "cuet-phy-mag-ampere-37", "subtopic": "Application to solenoid", "topic_name": "Ampere''s Circuital Law", "bloom_level": "apply", "options": [{"key": "A", "text": "1 A", "is_correct": false}, {"key": "B", "text": "2 A", "is_correct": false}, {"key": "C", "text": "3 A", "is_correct": false}, {"key": "D", "text": "≈ 4 A", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "With I = 1 A: B = 4π × 10⁻⁷ × 4000 × 1 = 16π × 10⁻⁴ ≈ 5 × 10⁻³ T = 0.005 T, which is four times too small.", "misconception": "Calculation error in unit conversion of n"}, {"option_key": "B", "hint": "With I = 2 A: B ≈ 0.01 T, which is half the required field. The correct current is about 4 A.", "misconception": "Arithmetic error giving half the required value"}, {"option_key": "C", "hint": "With I = 3 A: B ≈ 0.015 T, which is less than 0.02 T. The exact answer is 0.02/(μ₀ × 4000) ≈ 4 A.", "misconception": "Rounding error in the calculation"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "Based on the scenario, what is the ratio of the magnetic field at the inner radius to that at the outer radius of the toroid?", "explanation": "The magnetic field inside a toroid at radius r is B = μ₀NI/(2πr). At the inner radius a = 8 cm: B_inner = μ₀NI/(2π × 0.08). At the outer radius b = 12 cm: B_outer = μ₀NI/(2π × 0.12). Ratio = B_inner/B_outer = 0.12/0.08 = 3/2.", "correct_answer": "B", "concept_tags": ["scenario", "toroid", "field-ratio", "radial-variation"], "payload": {"question_id": "cuet-phy-mag-ampere-38", "subtopic": "Application to toroid", "topic_name": "Ampere''s Circuital Law", "bloom_level": "analyze", "options": [{"key": "A", "text": "1 : 1", "is_correct": false}, {"key": "B", "text": "3 : 2", "is_correct": true}, {"key": "C", "text": "2 : 3", "is_correct": false}, {"key": "D", "text": "4 : 3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The field is not uniform in a toroid. B ∝ 1/r, so the field is stronger at the inner radius (smaller r).", "misconception": "Treating the toroid field as uniform like a solenoid"}, {"option_key": "C", "hint": "This is the inverse ratio. Since B ∝ 1/r, B_inner/B_outer = r_outer/r_inner = 12/8 = 3/2, not 2/3.", "misconception": "Inverting the ratio (using r_inner/r_outer instead of r_outer/r_inner)"}, {"option_key": "D", "hint": "The ratio depends on the radii: 12/8 = 3/2, not 4/3. Check the given values: inner = 8 cm, outer = 12 cm.", "misconception": "Using incorrect radius values"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "easy", "question_text": "Arrange the following steps in the correct logical order for applying Ampere''s circuital law to find the magnetic field inside a solenoid:", "explanation": "The correct sequence is: (1) Identify the symmetry → the solenoid has translational symmetry along its axis with B uniform inside and zero outside. (2) Choose the Amperian loop → a rectangular loop with one side inside (parallel to axis) and one side outside. (3) Calculate the enclosed current → nLI, where nL turns pass through the loop area. (4) Evaluate the line integral → only the inside parallel side contributes: BL. (5) Apply Ampere''s law → BL = μ₀nLI, giving B = μ₀nI.", "correct_answer": "A", "concept_tags": ["logical-sequence", "solenoid", "methodology"], "payload": {"question_id": "cuet-phy-mag-ampere-39", "subtopic": "Application to solenoid", "topic_name": "Ampere''s Circuital Law", "bloom_level": "understand", "options": [{"key": "A", "text": "Q → P → S → T → R", "is_correct": true}, {"key": "B", "text": "P → Q → T → S → R", "is_correct": false}, {"key": "C", "text": "Q → S → P → R → T", "is_correct": false}, {"key": "D", "text": "S → P → Q → T → R", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "You must identify symmetry (Q) before choosing the loop (P). The loop choice depends on the symmetry identified.", "misconception": "Choosing the loop before understanding the symmetry"}, {"option_key": "C", "hint": "You cannot calculate the enclosed current (S) before choosing the Amperian loop (P), since the enclosed current depends on which loop you choose.", "misconception": "Calculating enclosed current before defining the loop"}, {"option_key": "D", "hint": "Starting with enclosed current calculation (S) is premature. First identify symmetry (Q), then choose the appropriate loop (P).", "misconception": "Jumping to calculation before setting up the problem"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "hard", "question_text": "Arrange the following developments in the correct historical and logical sequence that led from Ampere''s law to Maxwell''s equations:", "explanation": "The correct sequence is: (1) Oersted discovers that electric current produces a magnetic field (1820). (2) Ampere formulates the circuital law relating ∮B⃗·dl⃗ to enclosed current. (3) Gauss''s law is formulated as the electrostatic analogue. (4) Maxwell identifies the inconsistency of Ampere''s law for non-steady currents (charging capacitor problem). (5) Maxwell introduces displacement current and completes the equations.", "correct_answer": "C", "concept_tags": ["logical-sequence", "historical-development", "maxwell-equations", "limitations"], "payload": {"question_id": "cuet-phy-mag-ampere-40", "subtopic": "Limitations", "topic_name": "Ampere''s Circuital Law", "bloom_level": "analyze", "options": [{"key": "A", "text": "S → Q → T → P → R", "is_correct": false}, {"key": "B", "text": "Q → T → S → R → P", "is_correct": false}, {"key": "C", "text": "Q → S → T → P → R", "is_correct": true}, {"key": "D", "text": "T → Q → S → P → R", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Oersted''s discovery (Q) preceded Ampere''s law (S). Oersted first showed current produces magnetism, then Ampere quantified it.", "misconception": "Placing Ampere''s law before Oersted''s discovery"}, {"option_key": "B", "hint": "Maxwell must first identify the inconsistency (P) before introducing the fix — displacement current (R). The order P → R is correct, not R → P.", "misconception": "Reversing the order of identifying the problem and its solution"}, {"option_key": "D", "hint": "Gauss''s law (T) in its general form was developed after Oersted''s discovery (Q) and Ampere''s work (S), not before.", "misconception": "Placing Gauss''s law before the magnetic discoveries"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The magnetic field inside a long solenoid carrying current I with n turns per unit length is given by:", "explanation": "For an ideal long solenoid, applying Ampere''s circuital law gives B = μ₀nI, where n is the number of turns per unit length, I is the current, and μ₀ is the permeability of free space.", "correct_answer": "A", "concept_tags": ["solenoid", "magnetic field formula", "Ampere''s law"], "payload": {"question_id": "cuet-phy-mag-solenoid-01", "subtopic": "Solenoid field formula (B=μ₀nI)", "topic_name": "Solenoid and Toroid", "bloom_level": "remember", "options": [{"key": "A", "value": "B = μ₀nI", "is_correct": true}, {"key": "B", "value": "B = μ₀NI", "is_correct": false}, {"key": "C", "value": "B = μ₀nI/2π", "is_correct": false}, {"key": "D", "value": "B = μ₀NI/2πr", "is_correct": false}], "elimination_hints": ["B uses total turns N, not turns per unit length n — dimensionally incorrect for the solenoid formula.", "C introduces 2π which appears in toroid/straight wire formulas, not solenoid.", "D is the formula for a toroid, not a solenoid."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The magnetic field outside an ideal infinitely long solenoid is:", "explanation": "For an ideal solenoid of infinite length, the magnetic field lines are confined entirely within the solenoid. By Ampere''s law, the field outside is zero because no net current is enclosed by an external Amperian loop.", "correct_answer": "B", "concept_tags": ["solenoid", "field outside solenoid"], "payload": {"question_id": "cuet-phy-mag-solenoid-02", "subtopic": "Field inside vs outside solenoid", "topic_name": "Solenoid and Toroid", "bloom_level": "remember", "options": [{"key": "A", "value": "Equal to the field inside", "is_correct": false}, {"key": "B", "value": "Zero", "is_correct": true}, {"key": "C", "value": "Half the field inside", "is_correct": false}, {"key": "D", "value": "Inversely proportional to distance from axis", "is_correct": false}], "elimination_hints": ["A is wrong because the field is concentrated inside, not equally distributed.", "C is arbitrary — there is no half-field relation for an ideal solenoid exterior.", "D describes the field of a long straight wire, not the exterior of a solenoid."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A toroid is essentially a solenoid bent into the shape of a:", "explanation": "A toroid is formed by bending a solenoid into a closed circular ring (doughnut shape). This ensures that the magnetic field is entirely confined within the core with no external field.", "correct_answer": "C", "concept_tags": ["toroid", "solenoid", "geometry"], "payload": {"question_id": "cuet-phy-mag-solenoid-03", "subtopic": "Toroid vs solenoid comparison", "topic_name": "Solenoid and Toroid", "bloom_level": "remember", "options": [{"key": "A", "value": "Straight cylinder", "is_correct": false}, {"key": "B", "value": "Helix", "is_correct": false}, {"key": "C", "value": "Ring (doughnut/torus)", "is_correct": true}, {"key": "D", "value": "Flat disc", "is_correct": false}], "elimination_hints": ["A describes an unbent solenoid itself, not a toroid.", "B describes the winding pattern, not the overall shape of a toroid.", "D is a flat geometry with no enclosed volume for field confinement."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Inserting a ferromagnetic core inside a solenoid increases the magnetic field because:", "explanation": "A ferromagnetic core has high relative permeability (μᵣ >> 1). The field becomes B = μ₀μᵣnI, which is much larger than B = μ₀nI. The core''s domains align with the external field, greatly amplifying it.", "correct_answer": "D", "concept_tags": ["ferromagnetic core", "permeability", "solenoid"], "payload": {"question_id": "cuet-phy-mag-solenoid-04", "subtopic": "Effect of ferromagnetic core", "topic_name": "Solenoid and Toroid", "bloom_level": "understand", "options": [{"key": "A", "value": "It increases the current in the solenoid", "is_correct": false}, {"key": "B", "value": "It increases the number of turns per unit length", "is_correct": false}, {"key": "C", "value": "It reduces the length of the solenoid", "is_correct": false}, {"key": "D", "value": "Its high relative permeability multiplies the field", "is_correct": true}], "elimination_hints": ["A is incorrect — the core does not change the current flowing through the coil.", "B is incorrect — inserting a core does not alter the winding geometry.", "C is incorrect — the physical length of the solenoid remains unchanged."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Which of the following is a common application of a solenoid?", "explanation": "Solenoids are widely used as electromagnetic door locks, relay switches, MRI machines, and electromagnetic valves. An electromagnetic door lock uses a solenoid-based electromagnet to control the locking mechanism.", "correct_answer": "A", "concept_tags": ["solenoid", "applications", "electromagnet"], "payload": {"question_id": "cuet-phy-mag-solenoid-05", "subtopic": "Applications of solenoids", "topic_name": "Solenoid and Toroid", "bloom_level": "remember", "options": [{"key": "A", "value": "Electromagnetic door lock", "is_correct": true}, {"key": "B", "value": "Electric fuse", "is_correct": false}, {"key": "C", "value": "Rheostat", "is_correct": false}, {"key": "D", "value": "Potentiometer", "is_correct": false}], "elimination_hints": ["B is a safety device based on heating effect, not magnetism.", "C is a variable resistor that does not rely on solenoid principles.", "D measures EMF using the principle of null deflection, unrelated to solenoids."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The magnetic field inside a toroid of mean radius r, total N turns, carrying current I is:", "explanation": "Applying Ampere''s circuital law to a circular Amperian loop of radius r inside the toroid gives B × 2πr = μ₀NI, so B = μ₀NI/(2πr).", "correct_answer": "B", "concept_tags": ["toroid", "magnetic field", "Ampere''s law"], "payload": {"question_id": "cuet-phy-mag-solenoid-06", "subtopic": "Toroid field formula", "topic_name": "Solenoid and Toroid", "bloom_level": "remember", "options": [{"key": "A", "value": "B = μ₀NI", "is_correct": false}, {"key": "B", "value": "B = μ₀NI/(2πr)", "is_correct": true}, {"key": "C", "value": "B = μ₀nI/r", "is_correct": false}, {"key": "D", "value": "B = μ₀I/(2πr)", "is_correct": false}], "elimination_hints": ["A lacks the 2πr denominator required by Ampere''s law for a toroid.", "C mixes solenoid notation (n) with an extra r factor incorrectly.", "D is the formula for a long straight conductor, missing the N factor."]}}]'::jsonb, 'deploy-2026-03-05-b08');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A solenoid of length 0.5 m has 1000 turns and carries a current of 2 A. The magnetic field inside the solenoid is approximately:", "explanation": "n = N/L = 1000/0.5 = 2000 turns/m. B = μ₀nI = 4π × 10⁻⁷ × 2000 × 2 = 16π × 10⁻⁴ ≈ 5.03 × 10⁻³ T ≈ 5.0 × 10⁻³ T.", "correct_answer": "C", "concept_tags": ["solenoid", "numerical", "magnetic field calculation"], "payload": {"question_id": "cuet-phy-mag-solenoid-07", "subtopic": "Solenoid field formula (B=μ₀nI)", "topic_name": "Solenoid and Toroid", "bloom_level": "apply", "options": [{"key": "A", "value": "2.5 × 10⁻³ T", "is_correct": false}, {"key": "B", "value": "4.0 × 10⁻³ T", "is_correct": false}, {"key": "C", "value": "5.0 × 10⁻³ T", "is_correct": true}, {"key": "D", "value": "8.0 × 10⁻³ T", "is_correct": false}], "elimination_hints": ["A results from using n = 1000 instead of 2000, i.e., forgetting to divide by length.", "B comes from an arithmetic error in multiplying the factors.", "D is approximately double the correct value."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "If the current through a solenoid is doubled and the number of turns per unit length is halved, the magnetic field inside the solenoid will:", "explanation": "B = μ₀nI. If n → n/2 and I → 2I, then B'' = μ₀(n/2)(2I) = μ₀nI = B. The magnetic field remains unchanged.", "correct_answer": "D", "concept_tags": ["solenoid", "proportionality", "magnetic field"], "payload": {"question_id": "cuet-phy-mag-solenoid-08", "subtopic": "Solenoid field formula (B=μ₀nI)", "topic_name": "Solenoid and Toroid", "bloom_level": "apply", "options": [{"key": "A", "value": "Double", "is_correct": false}, {"key": "B", "value": "Become four times", "is_correct": false}, {"key": "C", "value": "Become half", "is_correct": false}, {"key": "D", "value": "Remain the same", "is_correct": true}], "elimination_hints": ["A considers only the doubling of current but ignores the halving of n.", "B incorrectly squares the change in current.", "C considers only the halving of n but ignores the doubling of current."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a real (finite-length) solenoid, the magnetic field at the centre compared to that at its ends is approximately:", "explanation": "At the centre of a finite solenoid, B ≈ μ₀nI. At either end, the field is approximately half this value, i.e., B_end ≈ μ₀nI/2, because the solenoid extends in only one direction from the end.", "correct_answer": "A", "concept_tags": ["real solenoid", "finite solenoid", "end effects"], "payload": {"question_id": "cuet-phy-mag-solenoid-09", "subtopic": "Ideal vs real solenoid", "topic_name": "Solenoid and Toroid", "bloom_level": "understand", "options": [{"key": "A", "value": "Twice the field at the ends", "is_correct": true}, {"key": "B", "value": "Equal to the field at the ends", "is_correct": false}, {"key": "C", "value": "Three times the field at the ends", "is_correct": false}, {"key": "D", "value": "Half the field at the ends", "is_correct": false}], "elimination_hints": ["B would only be true for an infinite solenoid where the field is uniform everywhere inside.", "C has no theoretical basis — no factor of 3 arises in solenoid field analysis.", "D reverses the relationship — the centre field is stronger, not weaker."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The self-inductance of a solenoid with N total turns, length l, and cross-sectional area A is given by:", "explanation": "The flux through the solenoid is Φ = NBA = N(μ₀nI)A = N(μ₀N/l)IA = μ₀N²IA/l. Since L = Φ/I, we get L = μ₀N²A/l.", "correct_answer": "B", "concept_tags": ["self-inductance", "solenoid", "inductance formula"], "payload": {"question_id": "cuet-phy-mag-solenoid-10", "subtopic": "Self-inductance relation", "topic_name": "Solenoid and Toroid", "bloom_level": "remember", "options": [{"key": "A", "value": "L = μ₀NA/l", "is_correct": false}, {"key": "B", "value": "L = μ₀N²A/l", "is_correct": true}, {"key": "C", "value": "L = μ₀N²l/A", "is_correct": false}, {"key": "D", "value": "L = μ₀NA²/l", "is_correct": false}], "elimination_hints": ["A is missing the N² dependence — inductance depends on the square of turns.", "C inverts the roles of l and A, giving incorrect dimensions.", "D squares the area instead of the number of turns."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The magnetic field in the open space inside a toroid (the central empty region) is:", "explanation": "For an Amperian loop drawn inside the central empty region of a toroid, no current is enclosed (the loop does not thread through any turns). By Ampere''s law, B × 2πr = 0, so B = 0.", "correct_answer": "C", "concept_tags": ["toroid", "central region", "Ampere''s law"], "payload": {"question_id": "cuet-phy-mag-solenoid-11", "subtopic": "Toroid field formula", "topic_name": "Solenoid and Toroid", "bloom_level": "understand", "options": [{"key": "A", "value": "Maximum", "is_correct": false}, {"key": "B", "value": "Same as inside the windings", "is_correct": false}, {"key": "C", "value": "Zero", "is_correct": true}, {"key": "D", "value": "Half of the value inside the windings", "is_correct": false}], "elimination_hints": ["A is wrong — the field is confined to the toroid''s core, not the central space.", "B confuses the central hollow region with the core where windings exist.", "D has no theoretical basis; no half-field relation applies here."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A solenoid of length 1 m with 500 turns carries 4 A of current. If a soft iron core of relative permeability 800 is inserted, the magnetic field inside becomes approximately:", "explanation": "n = 500/1 = 500 turns/m. Without core: B₀ = μ₀nI = 4π × 10⁻⁷ × 500 × 4 = 8π × 10⁻⁴ T ≈ 2.51 × 10⁻³ T. With core: B = μᵣB₀ = 800 × 2.51 × 10⁻³ ≈ 2.01 T ≈ 2.0 T.", "correct_answer": "D", "concept_tags": ["ferromagnetic core", "relative permeability", "numerical"], "payload": {"question_id": "cuet-phy-mag-solenoid-12", "subtopic": "Effect of ferromagnetic core", "topic_name": "Solenoid and Toroid", "bloom_level": "apply", "options": [{"key": "A", "value": "2.5 × 10⁻³ T", "is_correct": false}, {"key": "B", "value": "0.25 T", "is_correct": false}, {"key": "C", "value": "0.5 T", "is_correct": false}, {"key": "D", "value": "2.0 T", "is_correct": true}], "elimination_hints": ["A is the field without the core — the core amplifies it by factor μᵣ = 800.", "B results from an error in the multiplication by the permeability factor.", "C underestimates the amplification provided by the iron core."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Which statement correctly distinguishes a solenoid from a toroid?", "explanation": "A key difference is that a toroid has zero magnetic field outside its core (both in the central region and exterior), while a real solenoid has a weak but non-zero field outside, especially near its ends.", "correct_answer": "A", "concept_tags": ["solenoid", "toroid", "comparison"], "payload": {"question_id": "cuet-phy-mag-solenoid-13", "subtopic": "Toroid vs solenoid comparison", "topic_name": "Solenoid and Toroid", "bloom_level": "understand", "options": [{"key": "A", "value": "A toroid has no external magnetic field, whereas a real solenoid has a weak external field", "is_correct": true}, {"key": "B", "value": "A solenoid always has stronger internal field than a toroid for identical parameters", "is_correct": false}, {"key": "C", "value": "A toroid requires no current to produce a magnetic field", "is_correct": false}, {"key": "D", "value": "The field inside a solenoid depends on its radius but not in a toroid", "is_correct": false}], "elimination_hints": ["B cannot be generally compared as the geometries and formulas differ fundamentally.", "C violates basic electromagnetic principles — current is always needed for a magnetic field.", "D is reversed — an ideal solenoid''s field is radius-independent, while a toroid''s field depends on radial position."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The magnetic field inside an ideal solenoid is:", "explanation": "Inside an ideal (infinite) solenoid, the magnetic field is uniform and parallel to the axis. It does not depend on the radial position within the solenoid. This is derived from Ampere''s law using a rectangular Amperian loop.", "correct_answer": "B", "concept_tags": ["ideal solenoid", "uniform field", "field properties"], "payload": {"question_id": "cuet-phy-mag-solenoid-14", "subtopic": "Ideal vs real solenoid", "topic_name": "Solenoid and Toroid", "bloom_level": "understand", "options": [{"key": "A", "value": "Non-uniform and radial", "is_correct": false}, {"key": "B", "value": "Uniform and parallel to the axis", "is_correct": true}, {"key": "C", "value": "Uniform and perpendicular to the axis", "is_correct": false}, {"key": "D", "value": "Zero at the centre and maximum near the walls", "is_correct": false}], "elimination_hints": ["A describes a field pattern that would violate the symmetry of the solenoid.", "C has the wrong direction — the field is along the axis, not perpendicular.", "D reverses the actual behaviour — the field is uniform throughout the interior."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "If the length of a solenoid is doubled while keeping the total number of turns and current constant, the magnetic field inside will:", "explanation": "B = μ₀nI = μ₀(N/l)I. If l → 2l with N and I constant, then n → N/(2l) = n/2. Therefore B'' = μ₀(n/2)I = B/2. The field is halved.", "correct_answer": "C", "concept_tags": ["solenoid", "proportionality", "turns per unit length"], "payload": {"question_id": "cuet-phy-mag-solenoid-15", "subtopic": "Solenoid field formula (B=μ₀nI)", "topic_name": "Solenoid and Toroid", "bloom_level": "apply", "options": [{"key": "A", "value": "Double", "is_correct": false}, {"key": "B", "value": "Remain the same", "is_correct": false}, {"key": "C", "value": "Become half", "is_correct": true}, {"key": "D", "value": "Become one-fourth", "is_correct": false}], "elimination_hints": ["A incorrectly assumes B is proportional to length.", "B ignores the change in turns per unit length when length changes.", "D would require both n and I to be halved, which is not the case."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A toroid with 2000 turns, mean radius 20 cm, carries a current of 5 A. The magnetic field at the centre of the toroid (in the empty space enclosed by the ring) is:", "explanation": "The magnetic field in the central open space of a toroid is zero. An Amperian loop drawn in this region does not enclose any current, so by Ampere''s law B = 0. The given numerical values are distractors.", "correct_answer": "D", "concept_tags": ["toroid", "central region", "Ampere''s law", "tricky"], "payload": {"question_id": "cuet-phy-mag-solenoid-16", "subtopic": "Toroid field formula", "topic_name": "Solenoid and Toroid", "bloom_level": "analyze", "options": [{"key": "A", "value": "10⁻² T", "is_correct": false}, {"key": "B", "value": "10⁻³ T", "is_correct": false}, {"key": "C", "value": "2 × 10⁻³ T", "is_correct": false}, {"key": "D", "value": "Zero", "is_correct": true}], "elimination_hints": ["A results from blindly applying B = μ₀NI/(2πr) without noting the region asked about.", "B is a numerical distractor that does not correspond to any valid calculation for this region.", "C is another distractor — any non-zero value is wrong for the central empty space."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Two solenoids P and Q have the same length and carry the same current. P has twice the number of turns as Q but half the cross-sectional area. The ratio of their self-inductances L_P/L_Q is:", "explanation": "L = μ₀N²A/l. For P: L_P = μ₀(2N)²(A/2)/l = μ₀ × 4N² × A/(2l) = 2μ₀N²A/l. For Q: L_Q = μ₀N²A/l. So L_P/L_Q = 2.", "correct_answer": "C", "concept_tags": ["self-inductance", "solenoid", "ratio", "comparison"], "payload": {"question_id": "cuet-phy-mag-solenoid-17", "subtopic": "Self-inductance relation", "topic_name": "Solenoid and Toroid", "bloom_level": "apply", "options": [{"key": "A", "value": "1:1", "is_correct": false}, {"key": "B", "value": "4:1", "is_correct": false}, {"key": "C", "value": "2:1", "is_correct": true}, {"key": "D", "value": "1:2", "is_correct": false}], "elimination_hints": ["A ignores the effect of different N and A values on inductance.", "B considers only the N² factor (4×) but forgets the halved area.", "D inverts the ratio — P has larger inductance, not smaller."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A solenoid is connected to a battery. If a soft iron rod is partially inserted into the solenoid, the rod will:", "explanation": "The magnetic field inside the solenoid is non-uniform at the ends. A ferromagnetic material is attracted towards regions of stronger field. The iron rod will be pulled inward towards the region of stronger and more uniform field.", "correct_answer": "A", "concept_tags": ["solenoid", "ferromagnetic", "force on core", "non-uniform field"], "payload": {"question_id": "cuet-phy-mag-solenoid-18", "subtopic": "Effect of ferromagnetic core", "topic_name": "Solenoid and Toroid", "bloom_level": "analyze", "options": [{"key": "A", "value": "Be pulled further inside the solenoid", "is_correct": true}, {"key": "B", "value": "Be pushed out of the solenoid", "is_correct": false}, {"key": "C", "value": "Remain stationary at its position", "is_correct": false}, {"key": "D", "value": "Start rotating about the solenoid axis", "is_correct": false}], "elimination_hints": ["B would occur for a diamagnetic material, not a ferromagnetic one.", "C ignores the force exerted by the non-uniform field on the magnetised rod.", "D has no physical basis — the axial symmetry produces no torque about the axis."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A toroid of inner radius 10 cm and outer radius 14 cm has 1500 turns and carries 3 A. The magnetic field at a radial distance of 16 cm from the centre of the toroid is:", "explanation": "The outer radius of the toroid is 14 cm. A point at 16 cm lies outside the toroid. For an Amperian loop outside the toroid, the net enclosed current is zero. Therefore B = 0 outside the toroid.", "correct_answer": "B", "concept_tags": ["toroid", "external field", "Ampere''s law"], "payload": {"question_id": "cuet-phy-mag-solenoid-19", "subtopic": "Toroid field formula", "topic_name": "Solenoid and Toroid", "bloom_level": "analyze", "options": [{"key": "A", "value": "5.6 × 10⁻³ T", "is_correct": false}, {"key": "B", "value": "Zero", "is_correct": true}, {"key": "C", "value": "2.8 × 10⁻³ T", "is_correct": false}, {"key": "D", "value": "1.4 × 10⁻³ T", "is_correct": false}], "elimination_hints": ["A results from using the toroid formula at r = 16 cm without recognising the point is outside.", "C is a computational distractor based on incorrect radius substitution.", "D is another numerical distractor — any non-zero answer is wrong outside the toroid."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-solenoid", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The energy stored per unit volume inside a solenoid is u = B²/(2μ₀). If the current through the solenoid is tripled, the energy density becomes:", "explanation": "B = μ₀nI, so B is proportional to I. Energy density u = B²/(2μ₀) is proportional to I². If I → 3I, then u → 9u. The energy density becomes 9 times the original value.", "correct_answer": "D", "concept_tags": ["energy density", "solenoid", "magnetic energy"], "payload": {"question_id": "cuet-phy-mag-solenoid-20", "subtopic": "Solenoid field formula (B=μ₀nI)", "topic_name": "Solenoid and Toroid", "bloom_level": "apply", "options": [{"key": "A", "value": "3 times the original", "is_correct": false}, {"key": "B", "value": "6 times the original", "is_correct": false}, {"key": "C", "value": "27 times the original", "is_correct": false}, {"key": "D", "value": "9 times the original", "is_correct": true}], "elimination_hints": ["A only considers the linear change in I, ignoring the B² dependence.", "B has no theoretical basis — 6 does not arise from squaring or cubing 3.", "C cubes instead of squaring — energy density depends on I², not I³."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A proton moving with velocity v enters a uniform magnetic field B perpendicular to its direction of motion. The path followed by the proton is:", "explanation": "When a charged particle enters a magnetic field perpendicular to its velocity, the magnetic force F = qv × B acts as a centripetal force. Since this force is always perpendicular to the velocity, it changes the direction but not the speed of the particle. This results in uniform circular motion. The radius of the circle is r = mv/(qB).", "correct_answer": "C", "concept_tags": ["circular-motion", "lorentz-force", "charged-particle-in-B"], "payload": {"question_id": "cuet-phy-mag-force-01", "subtopic": "motion of charge in magnetic field", "topic_name": "Force on Current and Moving Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "A straight line", "is_correct": false}, {"key": "B", "text": "A parabolic path", "is_correct": false}, {"key": "C", "text": "A circular path", "is_correct": true}, {"key": "D", "text": "A helical path", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A straight line would occur only if the velocity were parallel to B (zero force). Here v is perpendicular to B.", "misconception": "Thinking magnetic force does not deflect the particle"}, {"option_key": "B", "hint": "A parabolic path occurs under a constant force (like gravity). The magnetic force changes direction continuously, unlike gravity.", "misconception": "Confusing magnetic force with gravitational force"}, {"option_key": "D", "hint": "A helical path requires a velocity component along B. Since v is entirely perpendicular to B, the path is circular, not helical.", "misconception": "Assuming helical motion without a parallel velocity component"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The work done by a magnetic force on a charged particle moving in a magnetic field is:", "explanation": "The magnetic force F = qv × B is always perpendicular to the velocity of the charged particle. Since work done W = F · ds = F · v dt, and F is perpendicular to v, the dot product F · v = 0. Hence, the magnetic force does no work on a moving charge. It can only change the direction of velocity, not its magnitude.", "correct_answer": "C", "concept_tags": ["work-done", "magnetic-force", "perpendicular-force"], "payload": {"question_id": "cuet-phy-mag-force-02", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "Positive", "is_correct": false}, {"key": "B", "text": "Negative", "is_correct": false}, {"key": "C", "text": "Always zero", "is_correct": true}, {"key": "D", "text": "Depends on the magnitude of charge", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Magnetic force is always perpendicular to velocity. A perpendicular force cannot increase the kinetic energy or do positive work.", "misconception": "Assuming any force that acts on a moving particle does work"}, {"option_key": "B", "hint": "Negative work would slow down the particle. But the speed of a charged particle in a pure magnetic field remains constant.", "misconception": "Confusing magnetic force with a drag or resistive force"}, {"option_key": "D", "hint": "Regardless of the magnitude of charge, the magnetic force is always perpendicular to displacement, so work is always zero.", "misconception": "Thinking work depends on charge magnitude alone"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A straight conductor of length 0.5 m carrying a current of 2 A is placed perpendicular to a uniform magnetic field of 0.4 T. The force experienced by the conductor is:", "explanation": "Using F = BIL sinθ, where B = 0.4 T, I = 2 A, L = 0.5 m, and θ = 90° (perpendicular). F = 0.4 × 2 × 0.5 × sin90° = 0.4 × 2 × 0.5 × 1 = 0.4 N.", "correct_answer": "A", "concept_tags": ["force-on-conductor", "BIL-formula", "perpendicular-field"], "payload": {"question_id": "cuet-phy-mag-force-03", "subtopic": "force on current-carrying conductor (F=BIL sinθ)", "topic_name": "Force on Current and Moving Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "0.4 N", "is_correct": true}, {"key": "B", "text": "0.2 N", "is_correct": false}, {"key": "C", "text": "0.8 N", "is_correct": false}, {"key": "D", "text": "0.1 N", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This would result from using sinθ = 0.5 (i.e., θ = 30°), but the conductor is perpendicular to the field so sinθ = 1.", "misconception": "Using wrong angle in F = BIL sinθ"}, {"option_key": "C", "hint": "This is double the correct answer. Check that you are not multiplying any quantity twice.", "misconception": "Arithmetic error in multiplication"}, {"option_key": "D", "hint": "This is one-fourth of the correct value. Verify all substituted values: B = 0.4, I = 2, L = 0.5.", "misconception": "Incorrect substitution of given values"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A charged particle moving with velocity v enters a uniform magnetic field B perpendicular to its velocity. The magnetic force on the particle is:", "explanation": "The magnetic force on a moving charged particle is given by F = qv × B. When the velocity is perpendicular to the magnetic field (θ = 90°), sin 90° = 1, so F = qvB. This is the maximum force the magnetic field can exert on the charge.", "correct_answer": "A", "concept_tags": ["lorentz-force", "magnetic-force", "moving-charge"], "payload": {"question_id": "cuet-phy-mag-force-04", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "qvB", "is_correct": true}, {"key": "B", "text": "qvB/2", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": false}, {"key": "D", "text": "qv/B", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The factor of 1/2 does not appear in the Lorentz force formula. F = qvB sinθ has no such coefficient.", "misconception": "Confusing with kinetic energy formula which has a 1/2 factor"}, {"option_key": "C", "hint": "Force is zero only when the charge moves parallel to B (θ = 0°). Here the motion is perpendicular to B, so sinθ = 1.", "misconception": "Confusing perpendicular and parallel motion relative to B"}, {"option_key": "D", "hint": "Dimensionally, qv/B gives C·m/(s·T) which does not have units of force. The correct formula has B in the numerator.", "misconception": "Incorrectly placing B in the denominator"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Two long parallel conductors carry currents in the same direction. The force between them is:", "explanation": "When two parallel conductors carry currents in the same direction, the magnetic field produced by one conductor at the location of the other results in an attractive force between them. This can be verified using the right-hand rule: the field from one wire at the other wire''s location creates a force directed toward the first wire. Currents in opposite directions repel each other.", "correct_answer": "A", "concept_tags": ["parallel-conductors", "force-between-conductors", "attractive-force"], "payload": {"question_id": "cuet-phy-mag-force-05", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "Attractive", "is_correct": true}, {"key": "B", "text": "Repulsive", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": false}, {"key": "D", "text": "Attractive or repulsive depending on the magnitude of currents", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Repulsive force occurs between parallel conductors carrying currents in opposite directions. Same-direction currents always attract.", "misconception": "Confusing same-direction and opposite-direction current rules"}, {"option_key": "C", "hint": "Two current-carrying conductors always exert a force on each other. The force is zero only when one of the currents is zero.", "misconception": "Thinking parallel conductors do not interact magnetically"}, {"option_key": "D", "hint": "The nature of the force (attractive/repulsive) depends only on the relative direction of currents, not on their magnitudes.", "misconception": "Confusing the nature of force with its magnitude"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A proton moves parallel to a uniform magnetic field. The force acting on the proton is:", "explanation": "The magnetic force on a charged particle is F = qvB sinθ. When the particle moves parallel to B, the angle θ = 0°, and sin 0° = 0. Therefore, F = 0. A magnetic field exerts no force on a charge moving along the field direction.", "correct_answer": "B", "concept_tags": ["magnetic-force", "parallel-motion", "zero-force"], "payload": {"question_id": "cuet-phy-mag-force-06", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "qvB", "is_correct": false}, {"key": "B", "text": "Zero", "is_correct": true}, {"key": "C", "text": "qvB/2", "is_correct": false}, {"key": "D", "text": "qB/v", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "F = qvB applies only when v is perpendicular to B (θ = 90°). Here the motion is parallel, so sinθ = 0.", "misconception": "Ignoring the sinθ dependence in the Lorentz force"}, {"option_key": "C", "hint": "There is no 1/2 factor in the force formula, and regardless the force is zero when velocity is parallel to B.", "misconception": null}, {"option_key": "D", "hint": "This expression is dimensionally incorrect for force and does not correspond to any known formula.", "misconception": null}]}}]'::jsonb, 'deploy-2026-03-05-b08');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a velocity selector, electric and magnetic fields are applied perpendicular to each other and to the velocity of charged particles. A particle passes through undeflected when:", "explanation": "In a velocity selector, the electric force qE and the magnetic force qvB act in opposite directions on the charged particle. For the particle to pass undeflected, these forces must balance: qE = qvB, giving v = E/B. This condition is independent of the charge and mass of the particle, so only particles with velocity v = E/B pass through straight.", "correct_answer": "C", "concept_tags": ["velocity-selector", "electric-magnetic-balance", "undeflected-motion"], "payload": {"question_id": "cuet-phy-mag-force-07", "subtopic": "velocity selector", "topic_name": "Force on Current and Moving Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "v = B/E", "is_correct": false}, {"key": "B", "text": "v = EB", "is_correct": false}, {"key": "C", "text": "v = E/B", "is_correct": true}, {"key": "D", "text": "v = E²/B", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is the inverse of the correct relation. From qE = qvB, solve for v: v = E/B, not B/E.", "misconception": "Inverting the ratio when solving qE = qvB"}, {"option_key": "B", "hint": "Check dimensions: EB has units of V·T/m, which is not velocity. v = E/B has units (V/m)/(T) = m/s.", "misconception": "Multiplying instead of dividing E and B"}, {"option_key": "D", "hint": "This has incorrect dimensions. The balance condition qE = qvB gives a linear relation between v, E, and B.", "misconception": "Introducing an incorrect power of E"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An electron (charge e, mass m) and a proton (charge e, mass M) enter a uniform magnetic field perpendicularly with the same kinetic energy. The ratio of radii of their circular paths (rₑ/rₚ) is:", "explanation": "The radius of circular motion in a magnetic field is r = mv/(eB). Since kinetic energy K = ½mv², we get v = √(2K/m), so r = m√(2K/m)/(eB) = √(2mK)/(eB). Therefore rₑ/rₚ = √(m/M). Since the electron mass m is much smaller than proton mass M, the electron follows a much smaller circle.", "correct_answer": "C", "concept_tags": ["radius-ratio", "kinetic-energy", "electron", "proton", "circular-motion"], "payload": {"question_id": "cuet-phy-mag-force-08", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "m/M", "is_correct": false}, {"key": "B", "text": "M/m", "is_correct": false}, {"key": "C", "text": "√(m/M)", "is_correct": true}, {"key": "D", "text": "√(M/m)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This would be the ratio if r were directly proportional to mass (at same velocity). But at same kinetic energy, r = √(2mK)/(eB), giving a square-root dependence.", "misconception": "Using r = mv/(qB) without converting velocity in terms of kinetic energy"}, {"option_key": "B", "hint": "M/m > 1 would mean the electron has a larger radius than the proton, which contradicts the fact that the lighter particle has a smaller radius at equal KE.", "misconception": "Inverting the mass ratio"}, {"option_key": "D", "hint": "√(M/m) > 1 would imply rₑ > rₚ. Since the electron is lighter, it has less momentum at the same KE and hence a smaller radius.", "misconception": "Confusing which particle has the larger radius"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a velocity selector, a charged particle passes undeflected when:", "explanation": "In a velocity selector, crossed electric (E) and magnetic (B) fields are applied. The electric force qE and the magnetic force qvB act in opposite directions. The particle passes undeflected when these forces balance: qE = qvB, giving v = E/B. This condition is independent of the charge and mass of the particle.", "correct_answer": "C", "concept_tags": ["velocity-selector", "electric-field", "magnetic-field", "undeflected"], "payload": {"question_id": "cuet-phy-mag-force-09", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "v = B/E", "is_correct": false}, {"key": "B", "text": "v = EB", "is_correct": false}, {"key": "C", "text": "v = E/B", "is_correct": true}, {"key": "D", "text": "v = E²/B", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "B/E is the inverse of the correct answer. From qE = qvB, solving for v gives v = E/B, not B/E.", "misconception": "Inverting the ratio while solving qE = qvB"}, {"option_key": "B", "hint": "EB is dimensionally incorrect for velocity. E has units V/m and B has units T, so EB would have units V·T/m, not m/s.", "misconception": "Incorrectly combining E and B"}, {"option_key": "D", "hint": "E²/B does not follow from balancing electric and magnetic forces. The correct derivation gives v = E/B.", "misconception": null}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A charged particle of mass m and charge q moves in a circular orbit of radius r in a magnetic field B. The kinetic energy of the particle is:", "explanation": "For circular motion in a magnetic field: qvB = mv²/r, giving v = qBr/m. The kinetic energy is KE = ½mv² = ½m(qBr/m)² = q²B²r²/(2m). This shows that the kinetic energy depends on the square of the charge, field, and radius, and inversely on the mass.", "correct_answer": "D", "concept_tags": ["circular-motion", "kinetic-energy", "radius-momentum-relation"], "payload": {"question_id": "cuet-phy-mag-force-10", "subtopic": "motion of charge in magnetic field", "topic_name": "Force on Current and Moving Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "qBr/m", "is_correct": false}, {"key": "B", "text": "q²B²r/(2m)", "is_correct": false}, {"key": "C", "text": "qB²r²/(2m)", "is_correct": false}, {"key": "D", "text": "q²B²r²/(2m)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This has dimensions of velocity, not energy. Kinetic energy must have dimensions of kg·m²/s².", "misconception": "Confusing velocity with kinetic energy"}, {"option_key": "B", "hint": "Check the power of r. From v = qBr/m, v² involves r², not r.", "misconception": "Missing a factor of r in the derivation"}, {"option_key": "C", "hint": "Check the power of q. From v = qBr/m, v² involves q², not q.", "misconception": "Missing a factor of q in the derivation"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a cyclotron, a proton is accelerated to high speeds. The time period of revolution of the proton in the magnetic field is independent of:", "explanation": "In a cyclotron, the time period T = 2πm/(qB). This expression shows that T depends on the mass m, charge q, and magnetic field B, but is independent of the speed (or kinetic energy) of the particle and the radius of its circular path. This independence of speed from the time period is the fundamental principle that allows the cyclotron to work with a fixed-frequency oscillating electric field.", "correct_answer": "A", "concept_tags": ["cyclotron", "time-period", "frequency-independence"], "payload": {"question_id": "cuet-phy-mag-force-11", "subtopic": "cyclotron", "topic_name": "Force on Current and Moving Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "Speed and radius of the circular path", "is_correct": true}, {"key": "B", "text": "Mass of the particle", "is_correct": false}, {"key": "C", "text": "Charge of the particle", "is_correct": false}, {"key": "D", "text": "Magnetic field strength", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "T = 2πm/(qB) explicitly contains m in the numerator. Changing the mass changes the time period.", "misconception": "Thinking mass does not affect the cyclotron frequency"}, {"option_key": "C", "hint": "T = 2πm/(qB) contains q in the denominator. Changing the charge changes the time period.", "misconception": "Thinking charge does not affect the cyclotron frequency"}, {"option_key": "D", "hint": "T = 2πm/(qB) contains B in the denominator. A stronger field means a shorter time period.", "misconception": "Thinking the magnetic field does not affect the time period"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A straight conductor of length 0.5 m carrying a current of 2 A is placed in a uniform magnetic field of 0.4 T at an angle of 30° to the field. The force on the conductor is:", "explanation": "The force on a current-carrying conductor in a magnetic field is F = BIL sinθ. Substituting the given values: F = 0.4 × 2 × 0.5 × sin 30° = 0.4 × 2 × 0.5 × 0.5 = 0.2 N.", "correct_answer": "D", "concept_tags": ["force-on-conductor", "current-carrying-conductor", "magnetic-field", "numerical"], "payload": {"question_id": "cuet-phy-mag-force-12", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "0.4 N", "is_correct": false}, {"key": "B", "text": "0.1 N", "is_correct": false}, {"key": "C", "text": "0.8 N", "is_correct": false}, {"key": "D", "text": "0.2 N", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "0.4 N would be the answer if sinθ = 1 (θ = 90°). Here θ = 30°, so sin 30° = 0.5 must be included.", "misconception": "Forgetting the sinθ factor when the conductor is not perpendicular to B"}, {"option_key": "B", "hint": "0.1 N would result from using sin 30° twice or an arithmetic error. Check: F = 0.4 × 2 × 0.5 × 0.5 = 0.2 N.", "misconception": "Arithmetic error in multiplication"}, {"option_key": "C", "hint": "0.8 N would result from ignoring sin 30° and also doubling the result. F = BIL sinθ, not 2BIL.", "misconception": "Using an incorrect formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A charged particle moves in a helical path in a uniform magnetic field. This happens when the velocity of the particle:", "explanation": "When a charged particle enters a magnetic field with its velocity at an angle to the field (neither parallel nor perpendicular), the velocity component perpendicular to B causes circular motion while the component parallel to B remains unaffected. The combination of circular motion and uniform linear motion along B produces a helical (spiral) path.", "correct_answer": "D", "concept_tags": ["helical-motion", "velocity-components", "magnetic-field"], "payload": {"question_id": "cuet-phy-mag-force-13", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "Is perpendicular to B", "is_correct": false}, {"key": "B", "text": "Is parallel to B", "is_correct": false}, {"key": "C", "text": "Is zero", "is_correct": false}, {"key": "D", "text": "Has components both parallel and perpendicular to B", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "When velocity is purely perpendicular to B, the particle follows a circular path, not a helical one.", "misconception": "Confusing circular and helical paths"}, {"option_key": "B", "hint": "When velocity is parallel to B, there is no magnetic force and the particle moves in a straight line.", "misconception": "Not recognizing that parallel motion produces zero force"}, {"option_key": "C", "hint": "If velocity is zero, there is no motion at all and hence no path of any kind.", "misconception": null}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Two long parallel wires separated by a distance of 0.1 m carry currents of 5 A and 10 A in the same direction. The force per unit length between them is: (μ₀ = 4π × 10⁻⁷ T·m/A)", "explanation": "The force per unit length between two parallel current-carrying wires is F/L = μ₀I₁I₂/(2πd). Substituting: F/L = (4π × 10⁻⁷ × 5 × 10)/(2π × 0.1) = (4π × 10⁻⁷ × 50)/(0.2π) = (200π × 10⁻⁷)/(0.2π) = 1000 × 10⁻⁷ = 10⁻⁴ N/m = 1 × 10⁻⁴ N/m. Since the currents are in the same direction, the force is attractive.", "correct_answer": "B", "concept_tags": ["parallel-currents", "force-per-unit-length", "attractive-force"], "payload": {"question_id": "cuet-phy-mag-force-14", "subtopic": "force between parallel currents", "topic_name": "Force on Current and Moving Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "2 × 10⁻⁴ N/m, repulsive", "is_correct": false}, {"key": "B", "text": "1 × 10⁻⁴ N/m, attractive", "is_correct": true}, {"key": "C", "text": "1 × 10⁻⁴ N/m, repulsive", "is_correct": false}, {"key": "D", "text": "5 × 10⁻⁵ N/m, attractive", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Check your calculation. The factor 2π in the denominator should give 10⁻⁴, not 2 × 10⁻⁴. Also, same-direction currents attract.", "misconception": "Error in simplifying the 2π factor"}, {"option_key": "C", "hint": "The magnitude is correct, but same-direction currents attract each other, they do not repel.", "misconception": "Confusing the direction of force between parallel currents"}, {"option_key": "D", "hint": "This is half the correct value. Verify your substitution of I₁ and I₂ in the formula.", "misconception": "Using incorrect current values in the formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A proton (mass 1.67 × 10⁻²⁷ kg) moves with a speed of 5 × 10⁶ m/s perpendicular to a magnetic field of 0.5 T. The radius of the circular path described by the proton is (charge of proton = 1.6 × 10⁻¹⁹ C):", "explanation": "When a charged particle moves perpendicular to a magnetic field, it follows a circular path. The radius is given by r = mv/(qB). Substituting: r = (1.67 × 10⁻²⁷ × 5 × 10⁶) / (1.6 × 10⁻¹⁹ × 0.5) = (8.35 × 10⁻²¹) / (8.0 × 10⁻²⁰) = 0.104 m ≈ 0.1 m.", "correct_answer": "B", "concept_tags": ["circular-motion", "radius-of-path", "proton", "magnetic-field"], "payload": {"question_id": "cuet-phy-mag-force-15", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "0.01 m", "is_correct": false}, {"key": "B", "text": "0.1 m", "is_correct": true}, {"key": "C", "text": "1.0 m", "is_correct": false}, {"key": "D", "text": "0.05 m", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is off by a factor of 10. Re-check the calculation: r = mv/(qB) = (1.67 × 10⁻²⁷ × 5 × 10⁶)/(1.6 × 10⁻¹⁹ × 0.5) ≈ 0.1 m.", "misconception": "Arithmetic error in power-of-ten calculation"}, {"option_key": "C", "hint": "1.0 m is ten times the correct answer. Ensure proper handling of exponents in the numerator and denominator.", "misconception": "Arithmetic error in power-of-ten calculation"}, {"option_key": "D", "hint": "0.05 m results from an incorrect factor of 2. The formula r = mv/(qB) does not include any additional numerical factor.", "misconception": "Introducing an extraneous factor in the formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The force per unit length between two long parallel conductors carrying currents I₁ and I₂ separated by a distance d is given by:", "explanation": "The magnetic field produced by conductor 1 at the location of conductor 2 is B₁ = μ₀I₁/(2πd). The force per unit length on conductor 2 is F/L = B₁I₂ = μ₀I₁I₂/(2πd). This expression is fundamental and is used to define the SI unit of current (ampere).", "correct_answer": "B", "concept_tags": ["force-per-unit-length", "parallel-conductors", "ampere-definition"], "payload": {"question_id": "cuet-phy-mag-force-16", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "μ₀I₁I₂/(4πd)", "is_correct": false}, {"key": "B", "text": "μ₀I₁I₂/(2πd)", "is_correct": true}, {"key": "C", "text": "μ₀I₁I₂/(2πd²)", "is_correct": false}, {"key": "D", "text": "μ₀I₁I₂d/(2π)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The factor is 2π in the denominator, not 4π. The field of a long wire is B = μ₀I/(2πd), and force/length = BI₂ = μ₀I₁I₂/(2πd).", "misconception": "Confusing 2π (Biot-Savart for infinite wire) with 4π (Coulomb''s law constant)"}, {"option_key": "C", "hint": "The distance d appears to the first power, not squared. This is not an inverse-square law like Coulomb''s law.", "misconception": "Incorrectly applying inverse-square law to magnetic force between wires"}, {"option_key": "D", "hint": "Having d in the numerator would mean force increases with distance, which is physically incorrect. Force decreases as conductors are moved apart.", "misconception": "Placing d in the wrong part of the formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "An alpha particle (charge 2e, mass 4mₚ) and a proton (charge e, mass mₚ) are accelerated from rest through the same potential difference and then enter a uniform magnetic field perpendicular to their velocity. The ratio of the radii of their circular paths (rα/rₚ) is:", "explanation": "After acceleration through potential difference V, kinetic energy K = qV. So Kα = 2eV and Kₚ = eV. The radius of circular motion is r = √(2mK)/(qB). For alpha particle: rα = √(2 × 4mₚ × 2eV)/(2eB) = √(16mₚeV)/(2eB) = 4√(mₚeV)/(2eB). For proton: rₚ = √(2mₚeV)/(eB) = √(2mₚeV)/(eB). Therefore rα/rₚ = [4√(mₚeV)/(2eB)] / [√(2mₚeV)/(eB)] = [4/(2)] × [1/√2] = 2/√2 = √2 = 1:1 × √2. So rα/rₚ = √2.", "correct_answer": "C", "concept_tags": ["alpha-particle", "proton", "radius-ratio", "potential-difference", "circular-motion"], "payload": {"question_id": "cuet-phy-mag-force-17", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "1:1", "is_correct": false}, {"key": "B", "text": "2:1", "is_correct": false}, {"key": "C", "text": "√2 : 1", "is_correct": true}, {"key": "D", "text": "1 : √2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1:1 would require identical r values. Since the alpha particle has different mass and charge, r = √(2mK)/(qB) with K = qV gives different radii.", "misconception": "Assuming equal radii for particles accelerated through same potential"}, {"option_key": "B", "hint": "2:1 would result from r ∝ m/q without properly accounting for the velocity gained through the potential difference.", "misconception": "Not correctly relating kinetic energy to the potential difference for different charges"}, {"option_key": "D", "hint": "1:√2 is the inverse of the correct ratio. The alpha particle, with greater momentum, has the larger radius.", "misconception": "Inverting the ratio of radii"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A proton and an alpha particle (charge 2e, mass 4mₚ) enter a uniform magnetic field perpendicular to their velocities. If both have the same kinetic energy, the ratio of the radii of their circular paths (rₚ/rα) is:", "explanation": "The radius of circular motion is r = mv/(qB). Since KE = ½mv², we get v = √(2KE/m), so r = m√(2KE/m)/(qB) = √(2mKE)/(qB). For the proton: rₚ = √(2mₚKE)/(eB). For the alpha particle: rα = √(2 × 4mₚ × KE)/(2eB) = 2√(2mₚKE)/(2eB) = √(2mₚKE)/(eB). Therefore rₚ/rα = [√(2mₚKE)/(eB)] / [√(2mₚKE)/(eB)] = 1. The ratio is 1:1.", "correct_answer": "D", "concept_tags": ["radius-ratio", "kinetic-energy", "proton-alpha-comparison"], "payload": {"question_id": "cuet-phy-mag-force-18", "subtopic": "motion of charge in magnetic field", "topic_name": "Force on Current and Moving Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "1 : 2", "is_correct": false}, {"key": "B", "text": "2 : 1", "is_correct": false}, {"key": "C", "text": "1 : √2", "is_correct": false}, {"key": "D", "text": "1 : 1", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This would be correct if both had the same momentum, not the same kinetic energy. With equal KE, r = √(2mKE)/(qB).", "misconception": "Confusing equal kinetic energy with equal momentum"}, {"option_key": "B", "hint": "This is the inverse of option A. Neither is correct for equal kinetic energy conditions.", "misconception": "Inverting the ratio while still using the momentum formula"}, {"option_key": "C", "hint": "This would arise from an error in the mass or charge ratio. For an alpha particle, m = 4mₚ and q = 2e; √(4mₚ)/(2e) = √(mₚ)/e.", "misconception": "Algebraic error in evaluating √m/q for the alpha particle"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A charged particle enters a region where a uniform magnetic field B and a uniform electric field E are both present and mutually perpendicular. If the particle has charge q, mass m, and enters with velocity v = E/B perpendicular to both fields, but the electric field is suddenly switched off, the radius of the resulting circular path is:", "explanation": "Initially the particle moves undeflected with v = E/B (velocity selector condition). When the electric field is switched off, only the magnetic force acts. The particle moves in a circle with radius r = mv/(qB). Substituting v = E/B: r = m(E/B)/(qB) = mE/(qB²). This radius depends on the mass-to-charge ratio and the fields.", "correct_answer": "D", "concept_tags": ["velocity-selector", "circular-motion", "radius-formula"], "payload": {"question_id": "cuet-phy-mag-force-19", "subtopic": "velocity selector", "topic_name": "Force on Current and Moving Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "mE/(qB)", "is_correct": false}, {"key": "B", "text": "mB/(qE)", "is_correct": false}, {"key": "C", "text": "mE²/(qB²)", "is_correct": false}, {"key": "D", "text": "mE/(qB²)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Check dimensions: mE/(qB) has units of kg·(V/m)/(C·T) = kg·m/s² × s/(C) which is not length. You need r = mv/(qB) with v = E/B.", "misconception": "Forgetting to substitute v = E/B into the radius formula"}, {"option_key": "B", "hint": "This inverts E and B. The velocity is E/B, not B/E, so the radius involves E in the numerator and B² in the denominator.", "misconception": "Inverting the velocity selector relation"}, {"option_key": "C", "hint": "The radius is r = mv/(qB) = m(E/B)/(qB) = mE/(qB²). There is no E² term.", "misconception": "Squaring E instead of B in the substitution"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A wire of length L is bent into a semicircular loop and carries a current I. It is placed in a uniform magnetic field B directed perpendicular to the plane of the loop. The net force on the semicircular wire is:", "explanation": "For a curved wire in a uniform magnetic field, the net force equals the force on a straight wire connecting the two ends of the curve. The semicircular wire of length L has radius r = L/π. The straight-line distance between the two ends (the diameter) is 2r = 2L/π. Therefore, the net force is F = BI × (2L/π) = 2BIL/π. The direction follows from F = IL × B for the equivalent straight conductor.", "correct_answer": "A", "concept_tags": ["semicircular-loop", "net-force", "uniform-field", "equivalent-straight-wire"], "payload": {"question_id": "cuet-phy-mag-force-20", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "2BIL/π", "is_correct": true}, {"key": "B", "text": "BIL", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": false}, {"key": "D", "text": "πBIL", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "BIL would be the force if the entire wire length L were straight and perpendicular to B. But for a semicircle, the effective length is the chord (diameter) = 2L/π.", "misconception": "Using the arc length instead of the chord length for net force"}, {"option_key": "C", "hint": "Zero net force applies to a complete closed loop in a uniform field. A semicircle is not a closed loop, so the net force is not zero.", "misconception": "Confusing semicircular wire with a complete loop"}, {"option_key": "D", "hint": "πBIL greatly overestimates the force. The effective straight-line length is 2L/π, which is shorter than L, not longer.", "misconception": "Using an incorrect geometric relationship"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The work done by a magnetic force on a charged particle moving in a magnetic field is always zero.\n\nReason (R): The magnetic force on a moving charged particle is always perpendicular to its velocity.", "explanation": "Both A and R are true, and R is the correct explanation of A. The magnetic force F = qv × B is always perpendicular to the velocity v (since the cross product is perpendicular to both vectors). Work is defined as W = F · ds, where ds is along the velocity. Since F is perpendicular to v (and hence to ds), the dot product F · ds = 0 at every instant. Therefore the magnetic force does zero work. R directly explains why A is true.", "correct_answer": "A", "concept_tags": ["work-by-magnetic-force", "perpendicular-force", "lorentz-force"], "payload": {"question_id": "cuet-phy-mag-force-25", "subtopic": "Lorentz force", "topic_name": "Force on Current and Moving Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are true and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are true but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly explains A: work = F · ds = 0 precisely because F ⊥ v. The perpendicularity is the reason for zero work.", "misconception": "Failing to connect perpendicularity of force with zero work done"}, {"option_key": "C", "hint": "R is correct. The cross product v × B is always perpendicular to v by the definition of the cross product.", "misconception": "Thinking the magnetic force can have a component along velocity"}, {"option_key": "D", "hint": "A is correct. Since F ⊥ v always, W = ∫F · ds = 0. The magnetic force cannot change the kinetic energy of a particle.", "misconception": "Thinking magnetic force can do work on a charged particle"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The kinetic energy of a charged particle moving in a uniform magnetic field remains constant.\nReason (R): The magnetic force on a moving charge is always perpendicular to its velocity.", "explanation": "The assertion is correct: since the magnetic force does no work, the kinetic energy (and hence the speed) of the charged particle remains unchanged. The reason is also correct: F = qv × B is always perpendicular to v by the nature of the cross product. Furthermore, the reason correctly explains the assertion — it is precisely because the force is perpendicular to velocity that no work is done (W = F · ds = 0 when F ⊥ v), and therefore kinetic energy is conserved.", "correct_answer": "A", "concept_tags": ["kinetic-energy", "magnetic-force", "no-work", "perpendicular-force"], "payload": {"question_id": "cuet-phy-mag-force-26", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly explains A. The perpendicularity of F to v means W = F · v dt = 0, so KE is constant. The causal link is direct.", "misconception": "Failing to see the direct causal connection between perpendicular force and zero work"}, {"option_key": "C", "hint": "The reason is a fundamental property of the cross product (v × B is always perpendicular to v). R is definitely correct.", "misconception": "Doubting the perpendicularity of the magnetic force to velocity"}, {"option_key": "D", "hint": "The assertion is correct — speed and hence KE of a charged particle in a magnetic field do not change. This is experimentally verified.", "misconception": "Thinking magnetic field changes the kinetic energy of a charge"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): A charged particle moving parallel to a magnetic field experiences no magnetic force and continues in a straight line.\n\nReason (R): The magnetic force on a charged particle is given by F = qE, where E is the electric field.", "explanation": "Assertion A is true: when a charged particle moves parallel (or antiparallel) to B, the angle θ between v and B is 0° (or 180°), so F = qvB sinθ = 0. The particle experiences no deflection and moves in a straight line. Reason R is false: the magnetic force on a moving charge is F = qv × B (Lorentz force), not F = qE. The expression F = qE describes the electric force, not the magnetic force.", "correct_answer": "C", "concept_tags": ["parallel-motion", "zero-force", "lorentz-force", "electric-vs-magnetic"], "payload": {"question_id": "cuet-phy-mag-force-27", "subtopic": "Lorentz force", "topic_name": "Force on Current and Moving Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are true and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are true but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": true}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "R states an incorrect formula. The magnetic force is F = qv × B, not F = qE. F = qE is the electric force.", "misconception": "Confusing the electric force formula with the magnetic force formula"}, {"option_key": "B", "hint": "R is factually incorrect as it gives the electric force formula instead of the magnetic force formula.", "misconception": "Accepting an incorrect formula as true"}, {"option_key": "D", "hint": "A is correct: when v is parallel to B, sinθ = 0 in F = qvBsinθ, so F = 0 and the particle is undeflected.", "misconception": "Thinking a charged particle always experiences force in a magnetic field"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): A current-carrying closed loop placed in a uniform magnetic field experiences a net force of zero.\nReason (R): The force on a current-carrying conductor in a magnetic field is given by F = I(L × B), where L is the length vector of the conductor.", "explanation": "The assertion is correct: for a closed loop in a uniform magnetic field, the net force is the vector sum of forces on all elements, which equals I(∮dL) × B = I × 0 × B = 0, since the line integral of dL around a closed loop is zero. The reason is also correct: F = I(L × B) is indeed the expression for force on a straight current-carrying conductor. However, the reason by itself does not directly explain why the net force on a closed loop is zero — one also needs the fact that ∮dL = 0 for a closed loop in a uniform field. So R is not the complete explanation of A.", "correct_answer": "B", "concept_tags": ["closed-loop", "net-force-zero", "uniform-field", "force-on-conductor"], "payload": {"question_id": "cuet-phy-mag-force-28", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": true}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "While both statements are correct, R only gives the force formula for a conductor. It does not explain why the sum of all such forces on a closed loop is zero. The explanation requires ∮dL = 0.", "misconception": "Assuming the force formula alone explains the zero net force on a closed loop"}, {"option_key": "C", "hint": "R is indeed correct. F = I(L × B) is the standard expression for force on a current-carrying conductor in a uniform field.", "misconception": "Doubting the validity of the force formula"}, {"option_key": "D", "hint": "A is correct. A closed current loop in a uniform magnetic field has zero net force (though it may experience a torque).", "misconception": "Confusing torque with net force on a loop"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Charged particle moving parallel to B\n(Q) Charged particle moving perpendicular to B\n(R) Charged particle moving at angle θ (0° < θ < 90°) to B\n(S) Charged particle at rest in B\n\nColumn II:\n(1) Helical path\n(2) Circular path\n(3) Straight line (no force)\n(4) No motion", "explanation": "P → 3: When velocity is parallel to B, sinθ = 0, so F = 0 and the particle continues in a straight line. Q → 2: When velocity is perpendicular to B, the constant perpendicular force causes circular motion. R → 1: When velocity has both parallel and perpendicular components to B, the perpendicular component causes circular motion while the parallel component causes linear drift, resulting in a helical path. S → 4: A stationary charge (v = 0) experiences no magnetic force and remains at rest.", "correct_answer": "D", "concept_tags": ["motion-in-magnetic-field", "circular-motion", "helical-motion", "match-the-following"], "payload": {"question_id": "cuet-phy-mag-force-29", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "P→2, Q→3, R→1, S→4", "is_correct": false}, {"key": "B", "text": "P→3, Q→1, R→2, S→4", "is_correct": false}, {"key": "C", "text": "P→4, Q→2, R→1, S→3", "is_correct": false}, {"key": "D", "text": "P→3, Q→2, R→1, S→4", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "P→2 is wrong. A particle moving parallel to B experiences zero force and moves in a straight line, not a circle.", "misconception": "Confusing parallel and perpendicular motion in B"}, {"option_key": "B", "hint": "Q→1 is wrong. A particle moving perpendicular to B traces a circle, not a helix. A helix requires a velocity component along B.", "misconception": "Confusing circular and helical paths"}, {"option_key": "C", "hint": "P→4 is wrong. A particle moving parallel to B is not stationary — it continues in a straight line since there is no magnetic force.", "misconception": "Thinking no force means no motion"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) SI unit of magnetic field\n(Q) Force between two parallel conductors carrying 1 A each, separated by 1 m, per unit length\n(R) Radius of circular path of charge q, mass m, speed v in field B\n(S) Condition for a charged particle to pass undeflected through crossed E and B fields\n\nColumn II:\n(1) mv/(qB)\n(2) 2 × 10⁻⁷ N/m\n(3) v = E/B\n(4) Tesla (T)", "explanation": "P → 4: The SI unit of magnetic field is Tesla (T). Q → 2: Using F/L = μ₀I₁I₂/(2πd) with I₁ = I₂ = 1 A, d = 1 m: F/L = (4π × 10⁻⁷ × 1 × 1)/(2π × 1) = 2 × 10⁻⁷ N/m. This is the basis for the definition of the ampere. R → 1: The radius of circular motion is r = mv/(qB), obtained by equating qvB = mv²/r. S → 3: In a velocity selector, qE = qvB gives v = E/B.", "correct_answer": "C", "concept_tags": ["tesla", "ampere-definition", "radius-formula", "velocity-selector", "match-the-following"], "payload": {"question_id": "cuet-phy-mag-force-30", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "P→4, Q→1, R→2, S→3", "is_correct": false}, {"key": "B", "text": "P→4, Q→2, R→3, S→1", "is_correct": false}, {"key": "C", "text": "P→4, Q→2, R→1, S→3", "is_correct": true}, {"key": "D", "text": "P→2, Q→4, R→1, S→3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Q→1 is wrong. The force per unit length between two wires is a numerical value (2 × 10⁻⁷ N/m), not the expression mv/(qB) which gives the radius of circular motion.", "misconception": "Mixing up the radius formula with the force between parallel conductors"}, {"option_key": "B", "hint": "R→3 is wrong. The radius of circular path is r = mv/(qB), not v = E/B. The condition v = E/B applies to velocity selectors.", "misconception": "Confusing the radius formula with the velocity selector condition"}, {"option_key": "D", "hint": "P→2 is wrong. The SI unit of magnetic field is Tesla (4), not 2 × 10⁻⁷ N/m (which is the force per unit length between parallel conductors).", "misconception": "Confusing the unit of B with the force value used in defining the ampere"}]}}]'::jsonb, 'deploy-2026-03-05-b08');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "When a charged particle enters a uniform magnetic field at an angle θ (where 0° < θ < 90°) to the field direction, it follows a helical path with its axis along the magnetic field direction.", "explanation": "This statement is TRUE. When a charged particle enters a magnetic field at an angle θ to B, its velocity has two components: v‖ = vcosθ (along B) and v⊥ = vsinθ (perpendicular to B). The perpendicular component causes circular motion, while the parallel component causes uniform linear motion along B. The combination of circular motion perpendicular to B and linear motion along B produces a helical (spiral) path with its axis along B.", "correct_answer": "A", "concept_tags": ["helical-motion", "velocity-components", "angle-entry"], "payload": {"question_id": "cuet-phy-mag-force-31", "subtopic": "helical motion", "topic_name": "Force on Current and Moving Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The velocity component along B is unaffected by the magnetic force (F = qv × B has no component along B). This component causes forward drift while the perpendicular component causes circular motion, resulting in a helix.", "misconception": "Thinking the particle follows a circular path even when it has a velocity component along B"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The direction of force on a current-carrying conductor placed in a magnetic field can be determined using Fleming''s left-hand rule.", "explanation": "This statement is TRUE. Fleming''s left-hand rule states: if the forefinger points in the direction of the magnetic field (B), the middle finger points in the direction of current (I), then the thumb gives the direction of force (F) on the conductor. This rule is specifically used for determining the direction of force on a current-carrying conductor in a magnetic field (motor rule).", "correct_answer": "A", "concept_tags": ["flemings-left-hand-rule", "direction-of-force", "current-carrying-conductor"], "payload": {"question_id": "cuet-phy-mag-force-32", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Fleming''s left-hand rule is the standard rule for finding the direction of force on a current-carrying conductor in a magnetic field. It is widely used and correct.", "misconception": "Confusing Fleming''s left-hand rule (motor rule) with Fleming''s right-hand rule (generator/dynamo rule)"}, {"option_key": "C", "hint": "This is not a valid option for this question.", "misconception": null}, {"option_key": "D", "hint": "This is not a valid option for this question.", "misconception": null}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The force between two parallel wires carrying currents in opposite directions is attractive.", "explanation": "This statement is FALSE. When two parallel wires carry currents in opposite directions, the force between them is repulsive, not attractive. Using the right-hand rule and F = IL × B, the magnetic field produced by one wire at the location of the other wire creates a force that pushes the wires apart. The rule is: same-direction currents attract, opposite-direction currents repel.", "correct_answer": "B", "concept_tags": ["parallel-currents", "repulsive-force", "opposite-currents"], "payload": {"question_id": "cuet-phy-mag-force-33", "subtopic": "force between parallel currents", "topic_name": "Force on Current and Moving Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Apply the right-hand rule: the field from one wire at the other wire''s location, combined with the opposite current direction, gives a repulsive force. Same-direction currents attract; opposite-direction currents repel.", "misconception": "Confusing the rule for same and opposite direction currents"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "A magnetic field can change the speed of a charged particle moving through it.", "explanation": "This statement is FALSE. The magnetic force on a charged particle is F = qv × B, which is always perpendicular to the velocity. A perpendicular force changes only the direction of velocity, not its magnitude (speed). Since no work is done by the magnetic force (W = F · ds = 0 when F ⊥ ds), the kinetic energy and hence the speed remain constant.", "correct_answer": "B", "concept_tags": ["magnetic-force", "speed-constant", "no-work", "perpendicular-force"], "payload": {"question_id": "cuet-phy-mag-force-34", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The magnetic force is always perpendicular to velocity and does zero work. Since work-energy theorem gives ΔKE = W = 0, speed cannot change.", "misconception": "Assuming any force acting on a particle changes its speed"}, {"option_key": "C", "hint": "This is not a valid option for this question.", "misconception": null}, {"option_key": "D", "hint": "This is not a valid option for this question.", "misconception": null}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "A proton (mass = 1.67 × 10⁻²⁷ kg, charge = 1.6 × 10⁻¹⁹ C) moves in a circular path of radius 0.1 m in a magnetic field of 0.5 T. The speed of the proton is approximately ________ m/s.", "explanation": "For circular motion in a magnetic field: qvB = mv²/r, giving v = qBr/m. Substituting: v = (1.6 × 10⁻¹⁹ × 0.5 × 0.1)/(1.67 × 10⁻²⁷) = (8 × 10⁻²¹)/(1.67 × 10⁻²⁷) = 4.79 × 10⁶ ≈ 4.8 × 10⁶ m/s.", "correct_answer": "D", "concept_tags": ["circular-motion", "proton-speed", "radius-formula"], "payload": {"question_id": "cuet-phy-mag-force-35", "subtopic": "motion of charge in magnetic field", "topic_name": "Force on Current and Moving Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "4.8 × 10⁴", "is_correct": false}, {"key": "B", "text": "4.8 × 10⁵", "is_correct": false}, {"key": "C", "text": "4.8 × 10⁷", "is_correct": false}, {"key": "D", "text": "4.8 × 10⁶", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Check your powers of 10: (10⁻¹⁹ × 10⁻¹)/(10⁻²⁷) = 10⁻²⁰⁺²⁷ = 10⁷, not 10⁴.", "misconception": "Error in handling powers of 10"}, {"option_key": "B", "hint": "The exponent should be 6, not 5. Recount: 10⁻¹⁹ × 10⁻¹ = 10⁻²⁰; dividing by 10⁻²⁷ gives 10⁷; the coefficient 8/1.67 ≈ 4.8 adjusts this to ~4.8 × 10⁶.", "misconception": "Off-by-one error in exponent arithmetic"}, {"option_key": "C", "hint": "This would make the proton travel at nearly 1/6 the speed of light for a 0.5 T field and 0.1 m radius, which is too fast. Check the coefficient calculation.", "misconception": "Incorrect division of the numerical coefficient"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "One ampere is defined as that steady current which, when flowing through each of two infinitely long, straight, parallel conductors placed 1 m apart in vacuum, produces a force per unit length of _____ N/m between them.", "explanation": "The SI definition of one ampere is based on the force between two parallel current-carrying conductors. Using F/L = μ₀I₁I₂/(2πd), with I₁ = I₂ = 1 A and d = 1 m: F/L = (4π × 10⁻⁷ × 1 × 1)/(2π × 1) = 2 × 10⁻⁷ N/m. This value defines the ampere in the SI system.", "correct_answer": "D", "concept_tags": ["ampere-definition", "parallel-conductors", "force-per-unit-length", "SI-units"], "payload": {"question_id": "cuet-phy-mag-force-36", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "4π × 10⁻⁷", "is_correct": false}, {"key": "B", "text": "1 × 10⁻⁷", "is_correct": false}, {"key": "C", "text": "4 × 10⁻⁷", "is_correct": false}, {"key": "D", "text": "2 × 10⁻⁷", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "4π × 10⁻⁷ is the value of μ₀ (permeability of free space), not the force per unit length. F/L = μ₀I₁I₂/(2πd) = μ₀/(2π) = 2 × 10⁻⁷ N/m.", "misconception": "Confusing μ₀ with the force per unit length"}, {"option_key": "B", "hint": "1 × 10⁻⁷ is half the correct value. The calculation gives μ₀/(2π) = 4π × 10⁻⁷/(2π) = 2 × 10⁻⁷, not 1 × 10⁻⁷.", "misconception": "Arithmetic error in simplifying μ₀/(2π)"}, {"option_key": "C", "hint": "4 × 10⁻⁷ is twice the correct value. Carefully simplify: 4π × 10⁻⁷/(2π) = 2 × 10⁻⁷.", "misconception": "Cancellation error when dividing 4π by 2π"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "In a mass spectrometer, singly ionized ions of two isotopes of an element (masses m₁ = 20 u and m₂ = 22 u, where 1 u = 1.66 × 10⁻²⁷ kg) are accelerated through a potential difference of 10 kV and then enter a uniform magnetic field of 0.2 T perpendicular to their velocity. The ions travel in semicircular paths and strike a photographic plate. What is the separation between the two lines formed on the photographic plate?", "explanation": "After acceleration, KE = qV, so v = √(2qV/m). The radius of the semicircular path is r = mv/(qB) = (m/(qB))√(2qV/m) = √(2mV/q)/B. The separation on the plate equals the difference in diameters: Δx = 2r₂ − 2r₁ = (2/B)√(2V/q)(√m₂ − √m₁). With q = 1.6 × 10⁻¹⁹ C, V = 10⁴ V, B = 0.2 T: √(2V/q) = √(2 × 10⁴/(1.6 × 10⁻¹⁹)) = √(1.25 × 10²³) = 1.118 × 10¹¹·⁵. Computing: r = √(2mV/q)/B. For m₁ = 20 × 1.66 × 10⁻²⁷ = 3.32 × 10⁻²⁶ kg: r₁ = √(2 × 3.32 × 10⁻²⁶ × 10⁴/1.6 × 10⁻¹⁹)/0.2 = √(4.15 × 10⁻³)/0.2 = 0.0644/0.2 = 0.322 m. For m₂ = 22 × 1.66 × 10⁻²⁷ = 3.652 × 10⁻²⁶ kg: r₂ = √(2 × 3.652 × 10⁻²⁶ × 10⁴/1.6 × 10⁻¹⁹)/0.2 = √(4.565 × 10⁻³)/0.2 = 0.0676/0.2 = 0.338 m. Separation = 2(r₂ − r₁) = 2(0.338 − 0.322) = 2 × 0.016 = 0.032 m ≈ 3.2 cm.", "correct_answer": "B", "concept_tags": ["mass-spectrometer", "isotopes", "semicircular-path", "separation", "scenario-based"], "payload": {"question_id": "cuet-phy-mag-force-37", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Force on Current and Moving Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "1.6 cm", "is_correct": false}, {"key": "B", "text": "3.2 cm", "is_correct": true}, {"key": "C", "text": "6.4 cm", "is_correct": false}, {"key": "D", "text": "0.8 cm", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1.6 cm is the difference in radii (r₂ − r₁), not diameters. The separation on the photographic plate equals the difference in diameters: 2(r₂ − r₁).", "misconception": "Forgetting to multiply the radius difference by 2 for the diameter difference"}, {"option_key": "C", "hint": "6.4 cm is double the correct answer. Check that you are not multiplying by 4 instead of 2 when converting from radius to diameter difference.", "misconception": "Doubling the diameter difference instead of the radius difference"}, {"option_key": "D", "hint": "0.8 cm is too small. This may result from an error in the calculation of radii or forgetting to use the correct mass values.", "misconception": "Arithmetic error in computing the radii"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "What is the maximum kinetic energy (in MeV) that the protons can achieve in this cyclotron? (1 MeV = 1.6 × 10⁻¹³ J)", "explanation": "The maximum speed is achieved when the proton reaches the edge of the dee: v_max = qBR/m = (1.6 × 10⁻¹⁹ × 1.5 × 0.5)/(1.67 × 10⁻²⁷) = (1.2 × 10⁻¹⁹)/(1.67 × 10⁻²⁷) = 7.19 × 10⁷ m/s. Maximum KE = ½mv² = ½ × 1.67 × 10⁻²⁷ × (7.19 × 10⁷)² = ½ × 1.67 × 10⁻²⁷ × 5.17 × 10¹⁵ = 4.32 × 10⁻¹² J. Converting to MeV: 4.32 × 10⁻¹² / 1.6 × 10⁻¹³ = 27 MeV. Alternatively, KE = q²B²R²/(2m) = (1.6 × 10⁻¹⁹)² × (1.5)² × (0.5)² / (2 × 1.67 × 10⁻²⁷) = (2.56 × 10⁻³⁸ × 2.25 × 0.25)/(3.34 × 10⁻²⁷) = 1.44 × 10⁻³⁸/(3.34 × 10⁻²⁷) ≈ 4.31 × 10⁻¹² J ≈ 27 MeV.", "correct_answer": "C", "concept_tags": ["cyclotron", "maximum-kinetic-energy", "proton-acceleration", "dee-radius"], "payload": {"question_id": "cuet-phy-mag-force-38", "subtopic": "cyclotron", "topic_name": "Force on Current and Moving Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "13.5 MeV", "is_correct": false}, {"key": "B", "text": "54 MeV", "is_correct": false}, {"key": "C", "text": "27 MeV", "is_correct": true}, {"key": "D", "text": "6.75 MeV", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is half the correct answer. Ensure you are using KE = q²B²R²/(2m) and not missing any squared term.", "misconception": "Missing the square on one of the quantities in the KE formula"}, {"option_key": "B", "hint": "This is double the correct answer. Check the factor of 2 in the denominator of KE = ½mv².", "misconception": "Forgetting the factor of ½ in the kinetic energy formula"}, {"option_key": "D", "hint": "This is one-fourth of the correct value. Verify that you have squared both B and R in the formula.", "misconception": "Forgetting to square the magnetic field or radius"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "easy", "question_text": "Arrange the following steps in the correct order for determining the force on a current-carrying conductor placed in a magnetic field using the formula F = BIL sinθ.", "explanation": "The correct sequence is: (Step 2) First identify the given quantities: B, I, and L. (Step 4) Determine the angle θ between the current direction and the magnetic field. (Step 1) Substitute all values into F = BIL sinθ to calculate the magnitude. (Step 3) Finally, use Fleming''s left-hand rule to find the direction of the force.", "correct_answer": "B", "concept_tags": ["force-calculation-steps", "BIL-formula", "flemings-rule"], "payload": {"question_id": "cuet-phy-mag-force-39", "subtopic": "force on current-carrying conductor (F=BIL sinθ)", "topic_name": "Force on Current and Moving Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "2 → 1 → 4 → 3", "is_correct": false}, {"key": "B", "text": "2 → 4 → 1 → 3", "is_correct": true}, {"key": "C", "text": "4 → 2 → 3 → 1", "is_correct": false}, {"key": "D", "text": "3 → 2 → 4 → 1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "You cannot calculate F = BIL sinθ (step 1) before determining θ (step 4). The angle is needed for the substitution.", "misconception": "Attempting calculation before all variables are identified"}, {"option_key": "C", "hint": "You should identify B, I, and L (step 2) before determining the angle (step 4), as you need to know the setup first.", "misconception": "Starting with angle determination before understanding the physical setup"}, {"option_key": "D", "hint": "Fleming''s rule (step 3) gives direction, which is typically determined after computing the magnitude. You also need B and I first.", "misconception": "Determining force direction before identifying the physical quantities"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-force", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "hard", "question_text": "Arrange the following phenomena in order of increasing magnetic force experienced, from least to greatest, for identical charged particles (charge q, mass m) moving with speed v.", "explanation": "The magnetic force on a charged particle is F = qvB sinθ. As the angle θ between v and B increases from 0° to 90°, sinθ increases from 0 to 1. At θ = 0° (parallel): F = 0. At θ = 30°: F = 0.5qvB. At θ = 60°: F = 0.866qvB. At θ = 90° (perpendicular): F = qvB (maximum). The order from least to greatest force is: parallel (0°) → 30° → 60° → perpendicular (90°), i.e., 1 → 2 → 3 → 4.", "correct_answer": "D", "concept_tags": ["angle-dependence", "sinθ-variation", "magnetic-force-comparison"], "payload": {"question_id": "cuet-phy-mag-force-40", "subtopic": "Lorentz force", "topic_name": "Force on Current and Moving Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "4 → 3 → 2 → 1", "is_correct": false}, {"key": "B", "text": "1 → 3 → 2 → 4", "is_correct": false}, {"key": "C", "text": "2 → 1 → 3 → 4", "is_correct": false}, {"key": "D", "text": "1 → 2 → 3 → 4", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This is the order from greatest to least, but the question asks for least to greatest (increasing order).", "misconception": "Reversing the required ordering direction"}, {"option_key": "B", "hint": "sin60° > sin30°, so the force at 60° is greater than at 30°. Items 2 and 3 are in wrong order here.", "misconception": "Incorrectly ranking sin30° and sin60°"}, {"option_key": "C", "hint": "A particle moving parallel to B (item 1) has zero force, which is less than force at 30° (item 2). Item 1 should come first.", "misconception": "Thinking a parallel-moving particle experiences some force"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The deflection in a moving coil galvanometer is proportional to the current passing through it because the restoring torque is proportional to:", "explanation": "In a moving coil galvanometer, the restoring torque is provided by the phosphor-bronze spring and is proportional to the angle of deflection (τ = kθ). At equilibrium, the deflecting torque (NIAB) equals the restoring torque (kθ), giving θ = (NAB/k)I. Hence deflection is proportional to current because the restoring torque is proportional to the twist/deflection angle.", "correct_answer": "D", "concept_tags": ["moving coil galvanometer", "restoring torque", "deflection"], "payload": {"question_id": "cuet-phy-mag-devices-01", "subtopic": "working principle", "topic_name": "Moving Coil Galvanometer", "bloom_level": "understand", "options": [{"key": "A", "value": "The magnetic field intensity", "is_correct": false}, {"key": "B", "value": "The number of turns of the coil", "is_correct": false}, {"key": "C", "value": "The area of the coil", "is_correct": false}, {"key": "D", "value": "The angle of twist of the suspension", "is_correct": true}], "elimination_hints": ["Magnetic field, number of turns, and area are constants of the galvanometer—they don''t change with deflection.", "The restoring torque must vary with deflection for equilibrium to be achieved at different currents.", "Think about what physically changes as the coil rotates—only the twist angle changes."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The time period of a charged particle revolving in a cyclotron is independent of:", "explanation": "In a cyclotron, the time period T = 2πm/(qB). This expression shows that T depends only on mass (m), charge (q), and magnetic field (B). It does not depend on the speed or energy of the particle (non-relativistic case). This is the key principle that makes the cyclotron work -- particles take the same time per revolution regardless of their speed, allowing a fixed-frequency oscillating electric field to accelerate them.", "correct_answer": "C", "concept_tags": ["cyclotron-frequency", "time-period", "independence-of-speed"], "payload": {"question_id": "cuet-phy-mag-devices-02", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "remember", "options": [{"key": "A", "text": "Mass of the particle", "is_correct": false}, {"key": "B", "text": "Magnetic field strength", "is_correct": false}, {"key": "C", "text": "Speed of the particle", "is_correct": true}, {"key": "D", "text": "Charge of the particle", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The formula T = 2πm/(qB) explicitly contains mass m in the numerator, so the time period directly depends on mass.", "misconception": "Overlooking the mass dependence in the cyclotron frequency formula"}, {"option_key": "B", "hint": "Magnetic field B appears in the denominator of T = 2πm/(qB). Increasing B decreases the time period, so T depends on B.", "misconception": "Ignoring the role of magnetic field in determining the cyclotron period"}, {"option_key": "D", "hint": "Charge q is in the denominator of T = 2πm/(qB). A particle with larger charge has a shorter time period, so T does depend on charge.", "misconception": "Forgetting that charge influences the cyclotron frequency"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The material used for the suspension wire in a moving coil galvanometer is phosphor-bronze because it has:", "explanation": "Phosphor-bronze is used for the suspension wire/spring in a moving coil galvanometer because it has a very small restoring torque per unit twist (low torsional constant). This ensures high sensitivity—even a small current produces a noticeable deflection. While it is also non-magnetic and has low temperature coefficient, the primary reason is the small restoring torque.", "correct_answer": "B", "concept_tags": ["galvanometer construction", "phosphor-bronze", "sensitivity"], "payload": {"question_id": "cuet-phy-mag-devices-03", "subtopic": "Galvanometer construction", "topic_name": "Moving Coil Galvanometer", "bloom_level": "remember", "options": [{"key": "A", "value": "High electrical conductivity", "is_correct": false}, {"key": "B", "value": "Small restoring torque per unit twist", "is_correct": true}, {"key": "C", "value": "High magnetic permeability", "is_correct": false}, {"key": "D", "value": "Large Young''s modulus", "is_correct": false}], "elimination_hints": ["Copper has higher conductivity but is not used—so conductivity is not the key property.", "High magnetic permeability would interfere with the magnetic field, making it undesirable.", "Large Young''s modulus means stiffness, which would reduce sensitivity, not improve it."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In a moving coil galvanometer, the coil is wound on an aluminium frame to:", "explanation": "The coil in a moving coil galvanometer is wound on an aluminium frame to provide electromagnetic damping. When the coil rotates in the magnetic field, eddy currents are induced in the aluminium frame (which is a conductor). These eddy currents oppose the motion of the coil (by Lenz''s law), bringing the coil to rest quickly without oscillations. This is known as dead-beat behavior.", "correct_answer": "B", "concept_tags": ["electromagnetic damping", "eddy currents", "aluminium frame"], "payload": {"question_id": "cuet-phy-mag-devices-04", "subtopic": "Galvanometer construction", "topic_name": "Moving Coil Galvanometer", "bloom_level": "remember", "options": [{"key": "A", "value": "Increase the magnetic flux through the coil", "is_correct": false}, {"key": "B", "value": "Provide electromagnetic damping", "is_correct": true}, {"key": "C", "value": "Increase the moment of inertia of the coil", "is_correct": false}, {"key": "D", "value": "Make the coil lighter", "is_correct": false}], "elimination_hints": ["The frame is made of aluminium (a conductor)—think about what happens when a conductor moves in a magnetic field.", "Increasing moment of inertia would slow the response, which is not desirable.", "If making the coil lighter were the goal, a non-metallic frame would be even lighter."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A cyclotron is used to accelerate:", "explanation": "A cyclotron is used to accelerate charged particles such as protons, deuterons, and alpha particles. It cannot accelerate neutral particles (no Lorentz force) or electrons (their small mass causes relativistic effects at modest energies, making the cyclotron frequency condition invalid). The device uses a combination of electric and magnetic fields to accelerate charged particles to high energies.", "correct_answer": "B", "concept_tags": ["cyclotron", "charged-particles", "particle-accelerator"], "payload": {"question_id": "cuet-phy-mag-devices-05", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "remember", "options": [{"key": "A", "text": "Electrons", "is_correct": false}, {"key": "B", "text": "Protons and deuterons", "is_correct": true}, {"key": "C", "text": "Neutral atoms", "is_correct": false}, {"key": "D", "text": "Neutrons", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Electrons have very small mass (9.1 x 10^-31 kg), so they quickly reach relativistic speeds where their mass increases significantly, violating the constant cyclotron frequency condition.", "misconception": "Thinking cyclotron works for all charged particles regardless of mass"}, {"option_key": "C", "hint": "Neutral atoms have no net charge, so they experience no Lorentz force (F = qv x B = 0) and cannot be accelerated by electric or magnetic fields.", "misconception": "Forgetting that cyclotron requires charged particles"}, {"option_key": "D", "hint": "Neutrons are uncharged particles. The cyclotron relies on the magnetic force (qvB) to bend particle paths, which is zero for neutral particles.", "misconception": "Confusing neutrons with charged particles"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "To convert a galvanometer into a voltmeter, one should connect:", "explanation": "A galvanometer is converted into a voltmeter by connecting a high resistance in series with it. This limits the current through the galvanometer to its full-scale deflection current (Ig) when the desired maximum voltage V is applied. The required series resistance R = V/Ig - G, where G is the galvanometer resistance. The high series resistance ensures that the voltmeter draws negligible current from the circuit.", "correct_answer": "A", "concept_tags": ["galvanometer-conversion", "voltmeter", "series-resistance"], "payload": {"question_id": "cuet-phy-mag-devices-06", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "remember", "options": [{"key": "A", "text": "A high resistance in series", "is_correct": true}, {"key": "B", "text": "A low resistance in series", "is_correct": false}, {"key": "C", "text": "A high resistance in parallel", "is_correct": false}, {"key": "D", "text": "A low resistance in parallel", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "A low resistance in series would barely increase the total resistance, so the galvanometer would still draw too much current and could be damaged. The resistance must be high to limit current to Ig.", "misconception": "Not understanding that a voltmeter must have very high resistance"}, {"option_key": "C", "hint": "A high resistance in parallel would have little effect since most current would still flow through the lower-resistance galvanometer. Parallel connection is used for ammeter conversion.", "misconception": "Confusing series and parallel configurations for meter conversion"}, {"option_key": "D", "hint": "A low resistance in parallel (shunt) is used to convert a galvanometer into an ammeter, not a voltmeter.", "misconception": "Confusing ammeter and voltmeter conversion methods"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "When a shunt of resistance S is connected across a galvanometer of resistance G, the fraction of total current that passes through the galvanometer is:", "explanation": "When a shunt S is connected in parallel with galvanometer G, the current divides in the inverse ratio of resistances. The current through galvanometer Ig = I × S/(G + S). Therefore, the fraction Ig/I = S/(G + S). This shows that a smaller shunt diverts more current away from the galvanometer.", "correct_answer": "D", "concept_tags": ["shunt resistance", "current division", "parallel circuit"], "payload": {"question_id": "cuet-phy-mag-devices-07", "subtopic": "shunt resistance", "topic_name": "Moving Coil Galvanometer", "bloom_level": "understand", "options": [{"key": "A", "value": "G/(G + S)", "is_correct": false}, {"key": "B", "value": "G/S", "is_correct": false}, {"key": "C", "value": "S/G", "is_correct": false}, {"key": "D", "value": "S/(G + S)", "is_correct": true}], "elimination_hints": ["In a parallel combination, current through a branch is inversely proportional to its resistance.", "The galvanometer has resistance G, so less current flows through it when G is large—the fraction should decrease with increasing G.", "Check: if S = G, the fraction should be 1/2 (equal split). Only S/(G + S) gives G/(G+G) = 1/2."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a moving coil galvanometer, the restoring torque is provided by:", "explanation": "In a moving coil galvanometer, the coil experiences a deflecting torque (τ = NIAB) due to the magnetic field. The restoring torque is provided by a pair of phosphor-bronze springs (hair springs) attached to the coil. At equilibrium, the restoring torque (kθ) equals the deflecting torque (NIAB), giving θ = NIAB/k. The springs also serve as leads to carry current to and from the coil.", "correct_answer": "D", "concept_tags": ["moving-coil-galvanometer", "restoring-torque", "spring", "equilibrium"], "payload": {"question_id": "cuet-phy-mag-devices-08", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "understand", "options": [{"key": "A", "text": "The magnetic field", "is_correct": false}, {"key": "B", "text": "Gravity", "is_correct": false}, {"key": "C", "text": "The soft iron core", "is_correct": false}, {"key": "D", "text": "The phosphor-bronze spring", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The magnetic field produces the deflecting torque (τ = NIAB), not the restoring torque. The restoring mechanism must oppose the deflection.", "misconception": "Confusing deflecting torque with restoring torque"}, {"option_key": "B", "hint": "Gravity is not used as the restoring mechanism in a moving coil galvanometer. The instrument can work in any orientation because springs provide the restoring torque.", "misconception": "Confusing with gravity-based instruments"}, {"option_key": "C", "hint": "The soft iron core makes the magnetic field radial (uniform in all positions of the coil) to ensure linear deflection, but it does not provide the restoring torque.", "misconception": "Confusing the role of the iron core with the spring"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A galvanometer of resistance 100 Ω gives full-scale deflection for a current of 10 mA. The resistance to be connected in series to convert it into a voltmeter of range 0-100 V is:", "explanation": "To convert a galvanometer to a voltmeter, a high resistance R is connected in series. Using R = V/Ig - G, where V = 100 V, Ig = 10 mA = 0.01 A, and G = 100 Ω: R = 100/0.01 - 100 = 10000 - 100 = 9900 Ω. The total resistance of the voltmeter becomes G + R = 10000 Ω, ensuring that only Ig flows when V is applied across it.", "correct_answer": "D", "concept_tags": ["galvanometer-to-voltmeter", "series-resistance", "numerical-problem"], "payload": {"question_id": "cuet-phy-mag-devices-09", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "apply", "options": [{"key": "A", "text": "10000 Ω", "is_correct": false}, {"key": "B", "text": "1000 Ω", "is_correct": false}, {"key": "C", "text": "10 Ω", "is_correct": false}, {"key": "D", "text": "9900 Ω", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "10000 Ω is V/Ig = 100/0.01, which is the total resistance needed. But the question asks for the series resistance R alone, so you must subtract G: R = 10000 - 100 = 9900 Ω.", "misconception": "Forgetting to subtract the galvanometer resistance G from V/Ig"}, {"option_key": "B", "hint": "1000 Ω would give a total resistance of 1100 Ω, limiting the voltmeter range to only V = Ig x (G + R) = 0.01 x 1100 = 11 V, not 100 V.", "misconception": "Arithmetic error or using wrong formula"}, {"option_key": "C", "hint": "10 Ω is far too small. With R = 10 Ω, total resistance = 110 Ω, giving range V = 0.01 x 110 = 1.1 V only.", "misconception": "Confusing voltmeter conversion with ammeter conversion (where low resistance is used)"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A galvanometer has a resistance of 50 Ω and gives full-scale deflection for a current of 5 mA. To convert it into an ammeter reading up to 5 A, the shunt resistance required is:", "explanation": "To convert a galvanometer into an ammeter, a low resistance (shunt) S is connected in parallel. Using the formula S = Ig × G / (I − Ig), where Ig = 5 mA = 0.005 A, G = 50 Ω, and I = 5 A: S = (0.005 × 50) / (5 − 0.005) = 0.25 / 4.995 ≈ 0.05 Ω. Since 4.995 ≈ 5, we get S ≈ 0.05 Ω.", "correct_answer": "C", "concept_tags": ["ammeter conversion", "shunt resistance", "galvanometer"], "payload": {"question_id": "cuet-phy-mag-devices-10", "subtopic": "conversion to ammeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "apply", "options": [{"key": "A", "value": "0.5 Ω", "is_correct": false}, {"key": "B", "value": "0.005 Ω", "is_correct": false}, {"key": "C", "value": "0.05 Ω", "is_correct": true}, {"key": "D", "value": "5 Ω", "is_correct": false}], "elimination_hints": ["The shunt must be very small compared to the galvanometer resistance of 50 Ω.", "5 Ω is too large—it would not divert enough current away from the galvanometer.", "Use S = IgG/(I−Ig) and approximate I−Ig ≈ I when I >> Ig."]}}]'::jsonb, 'deploy-2026-03-05-b08');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The current sensitivity of a galvanometer can be increased by:", "explanation": "Current sensitivity is defined as θ/I = NAB/k. To increase it, we can increase N (number of turns), A (area of coil), B (magnetic field strength), or decrease k (torsional constant of the spring). Using a stronger magnetic field directly increases current sensitivity.", "correct_answer": "C", "concept_tags": ["current sensitivity", "galvanometer sensitivity"], "payload": {"question_id": "cuet-phy-mag-devices-11", "subtopic": "current sensitivity", "topic_name": "Moving Coil Galvanometer", "bloom_level": "understand", "options": [{"key": "A", "value": "Increasing the torsional constant of the spring", "is_correct": false}, {"key": "B", "value": "Decreasing the number of turns in the coil", "is_correct": false}, {"key": "C", "value": "Using a stronger magnetic field", "is_correct": true}, {"key": "D", "value": "Reducing the area of the coil", "is_correct": false}], "elimination_hints": ["Current sensitivity = NAB/k. Increasing k (denominator) would decrease sensitivity.", "Decreasing N or A would reduce the numerator, thus reducing sensitivity.", "Only an option that increases NAB or decreases k will increase sensitivity."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The current sensitivity of a moving coil galvanometer can be increased by:", "explanation": "Current sensitivity Is = NAB/k, where N is the number of turns, A is the area of the coil, B is the magnetic field strength, and k is the torsional spring constant. To increase current sensitivity, we can increase N, A, or B, or decrease k (use a weaker spring). Increasing the spring constant k would decrease the sensitivity, not increase it.", "correct_answer": "C", "concept_tags": ["current-sensitivity", "galvanometer", "NAB-by-k"], "payload": {"question_id": "cuet-phy-mag-devices-12", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "understand", "options": [{"key": "A", "text": "Increasing the spring constant k", "is_correct": false}, {"key": "B", "text": "Decreasing the number of turns N", "is_correct": false}, {"key": "C", "text": "Increasing the magnetic field strength B", "is_correct": true}, {"key": "D", "text": "Decreasing the area of the coil A", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Since Is = NAB/k, increasing k (denominator) would decrease the sensitivity, making the galvanometer less sensitive to small currents.", "misconception": "Confusing direct and inverse proportionality in the sensitivity formula"}, {"option_key": "B", "hint": "N appears in the numerator of Is = NAB/k. Decreasing N would reduce sensitivity, not increase it.", "misconception": "Incorrectly identifying N as being in the denominator"}, {"option_key": "D", "hint": "Area A is in the numerator of Is = NAB/k. A larger coil area increases the torque for a given current, increasing sensitivity.", "misconception": "Thinking smaller area gives better sensitivity"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The voltage sensitivity of a galvanometer of resistance G, having N turns of area A in magnetic field B with spring constant k is given by:", "explanation": "Voltage sensitivity Vs = deflection per unit voltage = θ/V. Since θ/I (current sensitivity) = NAB/k, and V = IR (where R is the total resistance = G for the galvanometer alone), we get Vs = θ/V = (θ/I) x (1/G) = NAB/(kG). Thus voltage sensitivity depends inversely on the galvanometer resistance, unlike current sensitivity.", "correct_answer": "C", "concept_tags": ["voltage-sensitivity", "galvanometer", "NAB-by-kG"], "payload": {"question_id": "cuet-phy-mag-devices-13", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "understand", "options": [{"key": "A", "text": "NAB/k", "is_correct": false}, {"key": "B", "text": "NABk/G", "is_correct": false}, {"key": "C", "text": "NAB/(kG)", "is_correct": true}, {"key": "D", "text": "NAG/(kB)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "NAB/k is the current sensitivity (θ/I), not the voltage sensitivity. Voltage sensitivity = current sensitivity / G = NAB/(kG).", "misconception": "Confusing current sensitivity with voltage sensitivity"}, {"option_key": "B", "hint": "This expression has k in the numerator. Since higher spring constant k means lower deflection per unit current, k must be in the denominator.", "misconception": "Placing k incorrectly in the formula"}, {"option_key": "D", "hint": "This expression has G in the numerator and B in the denominator, both of which are inverted. Higher B gives more torque (hence more sensitivity), and higher G gives less voltage sensitivity.", "misconception": "Swapping the positions of B and G"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A cyclotron''s oscillator frequency is 10 MHz. If the magnetic field is 0.5 T, the charge-to-mass ratio (q/m) of the particle being accelerated is approximately:", "explanation": "The cyclotron frequency is given by f = qB/(2πm), so q/m = 2πf/B. Substituting the values: q/m = 2π x 10 x 10^6 / 0.5 = 2 x 3.14 x 10^7 / 0.5 = 6.28 x 10^7 / 0.5 = 1.256 x 10^8 C/kg ≈ 1.26 x 10^8 C/kg. This is close to the q/m ratio of a proton (e/mp = 1.6 x 10^-19 / 1.67 x 10^-27 ≈ 0.96 x 10^8 C/kg), suggesting a slightly different ion.", "correct_answer": "B", "concept_tags": ["cyclotron-frequency", "charge-to-mass-ratio", "numerical"], "payload": {"question_id": "cuet-phy-mag-devices-14", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "apply", "options": [{"key": "A", "text": "6.28 x 10^7 C/kg", "is_correct": false}, {"key": "B", "text": "1.26 x 10^8 C/kg", "is_correct": true}, {"key": "C", "text": "3.14 x 10^8 C/kg", "is_correct": false}, {"key": "D", "text": "2.0 x 10^7 C/kg", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This value (6.28 x 10^7) equals 2πf but forgets to divide by B. The correct formula is q/m = 2πf/B, and you must divide by 0.5 T.", "misconception": "Forgetting to divide by the magnetic field B"}, {"option_key": "C", "hint": "This value (3.14 x 10^8) corresponds to dividing by B but using πf instead of 2πf, or an arithmetic error in the multiplication.", "misconception": "Incorrect substitution in the cyclotron frequency formula"}, {"option_key": "D", "hint": "This value is significantly off from the correct calculation. With f = 10^7 Hz and B = 0.5 T, q/m = 2π x 10^7 / 0.5 = 4π x 10^7 ≈ 1.26 x 10^8.", "misconception": "Major arithmetic error or using the wrong formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A galvanometer has a resistance of 50 Ω and gives full-scale deflection for a current of 1 mA. To convert it into an ammeter of range 0 to 5 A, the shunt resistance required is:", "explanation": "To convert a galvanometer to an ammeter, a shunt resistance S is connected in parallel. Using the formula S = Ig x G/(I - Ig), where Ig = 1 mA = 0.001 A, G = 50 Ω, and I = 5 A: S = 0.001 x 50 / (5 - 0.001) = 0.05 / 4.999 ≈ 0.01 Ω. Since Ig << I, we can approximate S ≈ Ig x G / I = 0.001 x 50 / 5 = 0.01 Ω.", "correct_answer": "A", "concept_tags": ["galvanometer-to-ammeter", "shunt-resistance", "numerical-problem"], "payload": {"question_id": "cuet-phy-mag-devices-15", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "apply", "options": [{"key": "A", "text": "0.01 Ω", "is_correct": true}, {"key": "B", "text": "0.05 Ω", "is_correct": false}, {"key": "C", "text": "1.0 Ω", "is_correct": false}, {"key": "D", "text": "50 Ω", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "0.05 Ω = Ig x G = 0.001 x 50. This is the numerator of the formula but you must divide by (I - Ig) ≈ 5 to get the shunt value.", "misconception": "Using S = Ig x G instead of the complete formula S = Ig x G/(I - Ig)"}, {"option_key": "C", "hint": "1.0 Ω is too high for a shunt. The shunt must be much smaller than the galvanometer resistance to divert most current away from the coil.", "misconception": "Not understanding that shunt resistance should be very small"}, {"option_key": "D", "hint": "Using S = G = 50 Ω means equal resistance in parallel, which would only double the range, not increase it 5000 times.", "misconception": "Thinking the shunt should equal the galvanometer resistance"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The maximum kinetic energy of a charged particle emerging from a cyclotron of radius R, magnetic field B, charge q, and mass m is:", "explanation": "In a cyclotron, the charged particle moves in a circular path where the magnetic force provides centripetal force: qvB = mv^2/R, giving v = qBR/m. The maximum kinetic energy is KE = (1/2)mv^2 = (1/2)m(qBR/m)^2 = q^2B^2R^2/(2m). Here R is the radius of the largest semicircular path (the dee radius).", "correct_answer": "A", "concept_tags": ["cyclotron", "kinetic-energy", "maximum-energy", "dee-radius"], "payload": {"question_id": "cuet-phy-mag-devices-16", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "apply", "options": [{"key": "A", "text": "q²B²R²/(2m)", "is_correct": true}, {"key": "B", "text": "qBR/(2m)", "is_correct": false}, {"key": "C", "text": "q²B²R²/(m)", "is_correct": false}, {"key": "D", "text": "qB²R²/(2m)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This expression has dimensions of velocity (m/s), not energy (kg m^2/s^2). The kinetic energy must involve squared terms of q, B, and R.", "misconception": "Confusing the expression for velocity with kinetic energy"}, {"option_key": "C", "hint": "This is twice the correct answer. KE = (1/2)mv^2 has the factor of 1/2, so the result should be q^2B^2R^2/(2m), not q^2B^2R^2/m.", "misconception": "Forgetting the factor of 1/2 in the kinetic energy formula"}, {"option_key": "D", "hint": "This expression is missing one factor of q. Since v = qBR/m, the KE = (1/2)m(qBR/m)^2 = q^2B^2R^2/(2m), requiring q squared.", "misconception": "Error in squaring the velocity expression"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A galvanometer of resistance 40 Ω gives full-scale deflection for a current of 2 mA. It is converted into a voltmeter of range 0–20 V and also into an ammeter of range 0–5 A. The ratio of the resistance of the voltmeter to the resistance of the ammeter is:", "explanation": "For the voltmeter: Total resistance Rv = V/Ig = 20/0.002 = 10,000 Ω. For the ammeter: The shunt S = IgG/(I − Ig) = (0.002 × 40)/(5 − 0.002) = 0.08/4.998 ≈ 0.016 Ω. Total ammeter resistance Ra = GS/(G + S) ≈ S = 0.016 Ω (since S << G). Ratio Rv/Ra = 10,000/0.016 = 625,000. Alternatively, Rv/Ra = (V/Ig) / [IgG/(I−Ig)] = V(I−Ig)/(Ig²G) ≈ VI/(Ig²G) = (20 × 5)/(0.000004 × 40) = 100/0.00016 = 625,000.", "correct_answer": "D", "concept_tags": ["voltmeter resistance", "ammeter resistance", "conversion"], "payload": {"question_id": "cuet-phy-mag-devices-17", "subtopic": "conversion to ammeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "apply", "options": [{"key": "A", "value": "250", "is_correct": false}, {"key": "B", "value": "2,500", "is_correct": false}, {"key": "C", "value": "62,500", "is_correct": false}, {"key": "D", "value": "625,000", "is_correct": true}], "elimination_hints": ["A voltmeter has very high resistance, an ammeter has very low resistance—the ratio should be a very large number.", "Options like 250 or 2,500 are too small for the ratio of a 10,000 Ω voltmeter to a ~0.016 Ω ammeter.", "Calculate each resistance separately: Rv = V/Ig and Ra ≈ IgG/I, then find the ratio."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A galvanometer has a coil of 200 turns, each of area 1.5 × 10⁻² m², and is placed in a magnetic field of 0.2 T. If the torsional constant of the spring is 1.2 N·m/rad, what is the current required to produce a deflection of 30°?", "explanation": "At equilibrium, NIAB = kθ. Converting 30° to radians: θ = 30 × π/180 = π/6 rad ≈ 0.5236 rad. So I = kθ/(NAB) = (1.2 × 0.5236)/(200 × 1.5 × 10⁻² × 0.2) = 0.6283/(200 × 0.003) = 0.6283/0.6 = 1.047 A ≈ 1.05 A.", "correct_answer": "D", "concept_tags": ["galvanometer deflection", "torque balance", "numerical problem"], "payload": {"question_id": "cuet-phy-mag-devices-18", "subtopic": "working principle", "topic_name": "Moving Coil Galvanometer", "bloom_level": "apply", "options": [{"key": "A", "value": "0.52 A", "is_correct": false}, {"key": "B", "value": "2.10 A", "is_correct": false}, {"key": "C", "value": "0.63 A", "is_correct": false}, {"key": "D", "value": "1.05 A", "is_correct": true}], "elimination_hints": ["Remember to convert degrees to radians: 30° = π/6 rad, not 30 directly.", "0.52 A would be the answer if you forgot to convert degrees to radians (using θ = 30 without conversion would give a different error).", "I = kθ/(NAB). Compute NAB = 200 × 0.015 × 0.2 = 0.6. Then I = 1.2 × (π/6) / 0.6."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A galvanometer of resistance 50 Ω and full-scale deflection current 2 mA is to be converted into an ammeter of range 0-10 A and a voltmeter of range 0-200 V. The ratio of shunt resistance to series resistance is:", "explanation": "For ammeter: S = Ig x G/(I - Ig) = 0.002 x 50/(10 - 0.002) ≈ 0.1/9.998 ≈ 0.01 Ω. For voltmeter: R = V/Ig - G = 200/0.002 - 50 = 100000 - 50 = 99950 Ω. Ratio S/R = 0.01/99950 ≈ 1 x 10^-7. Alternatively, S/R = [Ig x G/(I - Ig)] / [V/Ig - G] ≈ [Ig x G/I] / [V/Ig] = Ig^2 x G / (IV) = (0.002)^2 x 50 / (10 x 200) = 2 x 10^-7 / 2000 = 1 x 10^-7.", "correct_answer": "D", "concept_tags": ["ammeter-voltmeter-conversion", "shunt", "series-resistance", "ratio"], "payload": {"question_id": "cuet-phy-mag-devices-19", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "analyze", "options": [{"key": "A", "text": "1 x 10^-3", "is_correct": false}, {"key": "B", "text": "1 x 10^-5", "is_correct": false}, {"key": "C", "text": "1 x 10^-6", "is_correct": false}, {"key": "D", "text": "1 x 10^-7", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This would imply the shunt is only 1000 times smaller than the series resistance. Given the huge difference in conversion (ammeter needs ~0.01 Ω, voltmeter needs ~100000 Ω), the ratio should be much smaller.", "misconception": "Rough estimation without proper calculation"}, {"option_key": "B", "hint": "Verify your calculation: S ≈ 0.01 Ω and R ≈ 99950 Ω. The ratio 0.01/99950 is approximately 10^-7, not 10^-5.", "misconception": "Arithmetic error in the order of magnitude"}, {"option_key": "C", "hint": "Close but off by a factor of 10. Carefully recalculate: S/R = 0.01/99950 ≈ 1.0 x 10^-7.", "misconception": "Small arithmetic or rounding error"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A proton is accelerated in a cyclotron with magnetic field 1.5 T. The radius of the dees is 0.5 m. The maximum kinetic energy gained by the proton is approximately (mass of proton = 1.67 x 10^-27 kg, charge = 1.6 x 10^-19 C):", "explanation": "Maximum KE = q^2B^2R^2/(2m). Substituting: KE = (1.6 x 10^-19)^2 x (1.5)^2 x (0.5)^2 / (2 x 1.67 x 10^-27) = (2.56 x 10^-38) x 2.25 x 0.25 / (3.34 x 10^-27) = (2.56 x 10^-38 x 0.5625) / (3.34 x 10^-27) = 1.44 x 10^-38 / 3.34 x 10^-27 = 4.31 x 10^-12 J. Converting to MeV: 4.31 x 10^-12 / 1.6 x 10^-13 ≈ 26.9 MeV ≈ 27 MeV.", "correct_answer": "C", "concept_tags": ["cyclotron", "maximum-kinetic-energy", "proton", "numerical-calculation"], "payload": {"question_id": "cuet-phy-mag-devices-20", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "apply", "options": [{"key": "A", "text": "7 MeV", "is_correct": false}, {"key": "B", "text": "14 MeV", "is_correct": false}, {"key": "C", "text": "27 MeV", "is_correct": true}, {"key": "D", "text": "54 MeV", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "7 MeV is approximately 1/4 of the correct answer. Check if you used R = 0.25 m instead of 0.5 m, or missed squaring one of the terms.", "misconception": "Using R instead of R^2 in the kinetic energy formula"}, {"option_key": "B", "hint": "14 MeV is half the correct answer. Ensure you have squared both q and B correctly in q^2B^2R^2/(2m).", "misconception": "Forgetting to square one of the quantities"}, {"option_key": "D", "hint": "54 MeV is double the correct answer. Check that you included the factor of 2 in the denominator of KE = q^2B^2R^2/(2m).", "misconception": "Forgetting the factor of 1/2 in the kinetic energy expression"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): An ammeter is always connected in parallel with the circuit element through which current is to be measured.\nReason (R): An ammeter has very low resistance so that it does not significantly change the current in the circuit.", "explanation": "The assertion is false. An ammeter is always connected in series with the circuit element, not in parallel. If connected in parallel, its low resistance would create a short circuit. The reason is true—an ammeter does have very low resistance to minimize its effect on the circuit current. Since the assertion is false but the reason is true, the answer is D.", "correct_answer": "D", "concept_tags": ["ammeter", "series connection", "low resistance"], "payload": {"question_id": "cuet-phy-mag-devices-25", "subtopic": "conversion to ammeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "analyze", "options": [{"key": "A", "value": "Both A and R are true and R is the correct explanation of A", "is_correct": false}, {"key": "B", "value": "Both A and R are true but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "value": "A is true but R is false", "is_correct": false}, {"key": "D", "value": "A is false but R is true", "is_correct": true}], "elimination_hints": ["Think carefully: is an ammeter connected in series or parallel? A parallel connection with low resistance would short the element.", "The reason about low resistance is correct—ammeters must have low resistance to not alter the current being measured.", "Since the assertion contains a factual error (parallel instead of series), options A and B (which state A is true) can be eliminated."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): Increasing the number of turns of the coil in a galvanometer increases current sensitivity but may not increase voltage sensitivity.\nReason (R): Voltage sensitivity equals current sensitivity divided by the resistance of the galvanometer, and increasing turns increases resistance.", "explanation": "Both the assertion and reason are true, and the reason correctly explains the assertion. Current sensitivity = NAB/k, which increases with N. However, voltage sensitivity = NAB/(kR). When N increases, the resistance R of the coil also increases (roughly proportionally). So voltage sensitivity = NAB/(kR) may not increase because the increase in N in the numerator is offset by the increase in R in the denominator. The reason correctly identifies this relationship.", "correct_answer": "A", "concept_tags": ["current sensitivity", "voltage sensitivity", "number of turns"], "payload": {"question_id": "cuet-phy-mag-devices-26", "subtopic": "voltage sensitivity", "topic_name": "Moving Coil Galvanometer", "bloom_level": "analyze", "options": [{"key": "A", "value": "Both A and R are true and R is the correct explanation of A", "is_correct": true}, {"key": "B", "value": "Both A and R are true but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "value": "A is true but R is false", "is_correct": false}, {"key": "D", "value": "A is false but R is true", "is_correct": false}], "elimination_hints": ["Check current sensitivity formula: θ/I = NAB/k. Increasing N clearly increases this.", "Check voltage sensitivity formula: θ/V = NAB/(kR). If N doubles and R also doubles, voltage sensitivity stays the same.", "The reason provides the exact mathematical relationship that explains why voltage sensitivity may not increase—this makes R a correct explanation of A."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The cyclotron frequency does not depend on the speed of the charged particle. Reason (R): In a cyclotron, as the particle gains speed, the radius of its circular path increases proportionally, keeping the time period constant.", "explanation": "Both the Assertion and Reason are correct, and the Reason correctly explains the Assertion. The cyclotron frequency f = qB/(2πm) is independent of speed. This is because when a particle gains energy and moves faster (v increases), it moves to a larger radius orbit (r = mv/(qB)), so r increases proportionally with v. Since T = 2πr/v = 2πm/(qB), the v cancels out, making the period constant. This is the fundamental principle that allows the cyclotron to use a fixed-frequency oscillating electric field.", "correct_answer": "A", "concept_tags": ["cyclotron-frequency", "radius-speed-relation", "assertion-reasoning"], "payload": {"question_id": "cuet-phy-mag-devices-27", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The Reason directly explains why the frequency is independent of speed: the increase in radius exactly compensates for the increase in speed, so the time per revolution stays constant. This is a causal explanation.", "misconception": "Not recognizing the causal connection between the radius-speed relationship and constant frequency"}, {"option_key": "C", "hint": "The Reason is factually correct. In a cyclotron, r = mv/(qB), so r is directly proportional to v. The circumference (2πr) grows in proportion to v, keeping T = 2πr/v constant.", "misconception": "Doubting the relationship between radius and speed"}, {"option_key": "D", "hint": "The Assertion is correct: from f = qB/(2πm), the frequency clearly does not contain velocity v, confirming it is independent of speed.", "misconception": "Thinking cyclotron frequency depends on speed"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): Increasing the number of turns in a moving coil galvanometer always increases both its current sensitivity and voltage sensitivity. Reason (R): Current sensitivity is NAB/k and voltage sensitivity is NAB/(kG), and increasing N increases the resistance G of the coil.", "explanation": "The Assertion is incorrect. While increasing N does increase current sensitivity (Is = NAB/k), it also increases the coil resistance G (since G is proportional to N for a given wire). Voltage sensitivity Vs = NAB/(kG) = Is/G. As N increases, both NAB/k and G increase, and the net effect on Vs depends on the relative rates. In fact, since G is proportional to N (longer wire), Vs = NAB/(kG) may remain roughly constant or even decrease. So increasing N does NOT always increase voltage sensitivity. The Reason is correct: it correctly states both formulas and that increasing N increases G.", "correct_answer": "D", "concept_tags": ["current-sensitivity", "voltage-sensitivity", "number-of-turns", "galvanometer-design"], "payload": {"question_id": "cuet-phy-mag-devices-28", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The Assertion claims increasing N always increases both sensitivities. But since G also increases with N, voltage sensitivity Vs = NAB/(kG) may not increase. The Assertion is therefore incorrect.", "misconception": "Ignoring the effect of increased resistance when adding more turns"}, {"option_key": "B", "hint": "Since the Assertion is incorrect (voltage sensitivity does not necessarily increase with N), options involving ''A is correct'' cannot be right.", "misconception": "Not analyzing the voltage sensitivity formula carefully"}, {"option_key": "C", "hint": "The Reason correctly states the formulas and the fact that G increases with N. This is physically accurate since more turns mean longer wire and greater resistance.", "misconception": "Thinking the Reason is wrong about resistance increasing with turns"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Cyclotron frequency\n(Q) Shunt resistance for ammeter\n(R) Series resistance for voltmeter\n(S) Current sensitivity of galvanometer\n\nColumn II:\n(1) NAB/k\n(2) V/Ig - G\n(3) qB/(2πm)\n(4) Ig·G/(I - Ig)", "explanation": "P-3: Cyclotron frequency f = qB/(2πm). Q-4: Shunt resistance S = Ig·G/(I - Ig) for converting galvanometer to ammeter. R-2: Series resistance R = V/Ig - G for converting galvanometer to voltmeter. S-1: Current sensitivity = NAB/k, which is the deflection per unit current in a galvanometer.", "correct_answer": "B", "concept_tags": ["cyclotron-frequency", "ammeter-conversion", "voltmeter-conversion", "current-sensitivity", "match-the-following"], "payload": {"question_id": "cuet-phy-mag-devices-29", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "understand", "options": [{"key": "A", "text": "P-3, Q-2, R-4, S-1", "is_correct": false}, {"key": "B", "text": "P-3, Q-4, R-2, S-1", "is_correct": true}, {"key": "C", "text": "P-4, Q-3, R-1, S-2", "is_correct": false}, {"key": "D", "text": "P-1, Q-4, R-2, S-3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps Q and R. The shunt resistance formula contains Ig·G/(I - Ig) which is (4), while the series resistance formula is V/Ig - G which is (2). So Q matches 4, not 2.", "misconception": "Swapping the ammeter and voltmeter conversion formulas"}, {"option_key": "C", "hint": "P-4 would match cyclotron frequency to the shunt formula, which is dimensionally inconsistent. Cyclotron frequency has units of Hz = 1/s, while Ig·G/(I-Ig) has units of Ω.", "misconception": "Not checking dimensional consistency of the formulas"}, {"option_key": "D", "hint": "P-1 matches cyclotron frequency with NAB/k, which is the current sensitivity formula. Cyclotron frequency f = qB/(2πm) matches with (3).", "misconception": "Confusing cyclotron frequency with galvanometer sensitivity"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Magnetic field inside a long solenoid\n(Q) Magnetic field of a toroid (inside)\n(R) Cyclotron maximum KE\n(S) Deflecting torque in a galvanometer\n\nColumn II:\n(1) NIAB\n(2) μ₀nI (n = turns per unit length)\n(3) q²B²R²/(2m)\n(4) μ₀NI/(2πr)", "explanation": "P-2: The magnetic field inside a long solenoid is B = μ₀nI, where n is the number of turns per unit length. Q-4: Inside a toroid, B = μ₀NI/(2πr), where N is total turns and r is the radius of the toroidal path. R-3: Maximum kinetic energy from a cyclotron is q²B²R²/(2m). S-1: The deflecting torque on the coil in a galvanometer is τ = NIAB.", "correct_answer": "A", "concept_tags": ["solenoid", "toroid", "cyclotron-energy", "galvanometer-torque", "match-the-following"], "payload": {"question_id": "cuet-phy-mag-devices-30", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "analyze", "options": [{"key": "A", "text": "P-2, Q-4, R-3, S-1", "is_correct": true}, {"key": "B", "text": "P-4, Q-2, R-3, S-1", "is_correct": false}, {"key": "C", "text": "P-2, Q-4, R-1, S-3", "is_correct": false}, {"key": "D", "text": "P-2, Q-1, R-3, S-4", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This swaps P and Q. The solenoid field B = μ₀nI uses turns per unit length (n), while the toroid field B = μ₀NI/(2πr) uses total turns N and has r in the denominator.", "misconception": "Confusing the solenoid and toroid magnetic field formulas"}, {"option_key": "C", "hint": "R-1 would match cyclotron KE with NIAB (torque). The cyclotron KE expression q²B²R²/(2m) is (3), and NIAB is the galvanometer torque (1).", "misconception": "Swapping the cyclotron energy and galvanometer torque expressions"}, {"option_key": "D", "hint": "Q-1 would match toroid field with NIAB, which is the torque expression for a galvanometer. The toroid field is μ₀NI/(2πr), which is (4).", "misconception": "Not distinguishing between the torque formula and the toroid field formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The figure of merit of a galvanometer is defined as the current required to produce a unit deflection in the galvanometer.", "explanation": "This statement is TRUE. The figure of merit of a galvanometer is defined as the current required to produce one unit (one division) of deflection. Mathematically, figure of merit = k/(NAB), where k is the torsional constant, N is the number of turns, A is the area, and B is the magnetic field. A smaller figure of merit indicates a more sensitive galvanometer.", "correct_answer": "A", "concept_tags": ["figure of merit", "galvanometer sensitivity"], "payload": {"question_id": "cuet-phy-mag-devices-31", "subtopic": "figure of merit", "topic_name": "Moving Coil Galvanometer", "bloom_level": "remember", "options": [{"key": "A", "value": "True", "is_correct": true}, {"key": "B", "value": "False", "is_correct": false}, {"key": "C", "value": "---", "is_correct": false}, {"key": "D", "value": "---", "is_correct": false}], "elimination_hints": ["Recall: figure of merit = I/θ = k/(NAB). It represents current per unit deflection.", "This is a standard textbook definition—figure of merit is the reciprocal of current sensitivity."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The magnetic field inside a solenoid is uniform and parallel to the axis of the solenoid.", "explanation": "This statement is TRUE. Inside a long solenoid (ideal case), the magnetic field is uniform in both magnitude and direction. The field lines run parallel to the axis of the solenoid. This can be derived using Ampere''s law, which gives B = μ₀nI inside the solenoid (where n = N/L is the number of turns per unit length). Outside the solenoid, the field is approximately zero.", "correct_answer": "A", "concept_tags": ["solenoid", "uniform-magnetic-field", "field-direction"], "payload": {"question_id": "cuet-phy-mag-devices-32", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The field inside an ideal long solenoid is indeed uniform and axial. This is a standard result from Ampere''s law applied to a rectangular Amperian loop.", "misconception": "Confusing solenoid field with that of a bar magnet, where the field is non-uniform"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "An ideal voltmeter has zero resistance so that it does not draw any current from the circuit.", "explanation": "This statement is FALSE. An ideal voltmeter has infinite resistance (not zero resistance) so that it draws zero current from the circuit. Zero resistance is the characteristic of an ideal ammeter, not a voltmeter. A voltmeter with zero resistance would short-circuit the component across which it is connected.", "correct_answer": "B", "concept_tags": ["ideal voltmeter", "infinite resistance"], "payload": {"question_id": "cuet-phy-mag-devices-33", "subtopic": "conversion to voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "remember", "options": [{"key": "A", "value": "True", "is_correct": false}, {"key": "B", "value": "False", "is_correct": true}, {"key": "C", "value": "---", "is_correct": false}, {"key": "D", "value": "---", "is_correct": false}], "elimination_hints": ["Think about what happens if a voltmeter with zero resistance is connected in parallel—it would short-circuit the component.", "Zero resistance is the property of an ideal ammeter, not a voltmeter.", "For no current to flow through the voltmeter, its resistance must be as high as possible—ideally infinite."]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "A cyclotron can be used to accelerate electrons to high energies efficiently.", "explanation": "This statement is FALSE. A cyclotron cannot efficiently accelerate electrons because electrons have very small mass (9.1 x 10^-31 kg). Due to their low mass, electrons quickly reach relativistic speeds, at which point their mass increases significantly (relativistic mass increase). This causes the cyclotron frequency f = qB/(2πm) to decrease, and the particles go out of synchronization with the fixed-frequency oscillating electric field. This is a well-known limitation of the cyclotron.", "correct_answer": "B", "concept_tags": ["cyclotron", "electrons", "relativistic-effects", "limitation"], "payload": {"question_id": "cuet-phy-mag-devices-34", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Moving Coil Galvanometer", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Electrons have very small rest mass, so they reach relativistic speeds at relatively low energies. At relativistic speeds, the effective mass increases, changing the cyclotron frequency and causing loss of synchronization.", "misconception": "Thinking the cyclotron works for all charged particles without considering relativistic effects"}]}}]'::jsonb, 'deploy-2026-03-05-b08');

